export enum VoiceName {
  Kore = 'Kore',
  Puck = 'Puck',
  Charon = 'Charon',
  Fenrir = 'Fenrir',
  Zephyr = 'Zephyr'
}

export interface StorySegment {
  text: string;
  audioBuffer?: AudioBuffer;
  status: 'idle' | 'generating' | 'ready' | 'error';
}

export interface Story {
  title: string;
  content: string;
  segments: StorySegment[];
}

export interface PlaybackState {
  currentSegmentIndex: number;
  isPlaying: boolean;
  isLoading: boolean;
  voice: VoiceName;
}

import { GoogleGenAI, Modality } from "@google/genai";
import { VoiceName } from "../types";

const API_KEY = process.env.API_KEY || "";

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const generateSpeech = async (
  text: string, 
  voice: VoiceName, 
  audioContext: AudioContext
): Promise<AudioBuffer> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Gemini 2.5 Flash Preview TTS is the model for speech generation
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Read this story segment naturally and expressively: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("No audio data received from Gemini API");
  }

  const audioData = decode(base64Audio);
  // Gemini TTS returns raw PCM 24kHz mono by default
  const audioBuffer = await decodeAudioData(
    audioData,
    audioContext,
    24000,
    1
  );

  return audioBuffer;
};

declare const pdfjsLib: any;
declare const mammoth: any;

export const parseFile = async (file: File): Promise<string> => {
  const extension = file.name.split('.').pop()?.toLowerCase();

  if (extension === 'txt') {
    return await file.text();
  } 

  if (extension === 'pdf') {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = "";
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const content = await page.getTextContent();
      const strings = content.items.map((item: any) => item.str);
      fullText += strings.join(" ") + "\n";
    }
    return fullText;
  }

  if (extension === 'docx') {
    const arrayBuffer = await file.arrayBuffer();
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value;
  }

  throw new Error("Unsupported file format. Please upload PDF, DOCX, or TXT.");
};

export const segmentText = (text: string): string[] => {
  // Split by double newlines or punctuation for natural reading segments
  // We avoid too long segments for API stability and better UX
  return text
    .split(/\n\s*\n|\.|\?|!/)
    .map(s => s.trim())
    .filter(s => s.length > 5); // Filter out tiny fragments
};

