import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, BookOpen, FileText, X, AlertCircle } from 'lucide-react';
import { Story, PlaybackState, VoiceName } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import { generateSpeech } from './services/geminiService';
import Reader from './components/Reader';

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voice: VoiceName.Kore
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  // Initialize AudioContext on first user interaction
  const getAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return audioContextRef.current;
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setPlayback(p => ({ ...p, isLoading: true }));
    setError(null);

    try {
      const text = await parseFile(file);
      const segments = segmentText(text);

      setStory({
        title: file.name.split('.')[0],
        content: text,
        segments: segments.map(s => ({ text: s, status: 'idle' }))
      });
      setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false, isLoading: false }));
    } catch (err: any) {
      setError(err.message || "Failed to process document");
      setPlayback(p => ({ ...p, isLoading: false }));
    }
  };

  const handlePastedStory = () => {
    if (!pastedText.trim()) return;
    const segments = segmentText(pastedText);
    setStory({
      title: "Pasted Story",
      content: pastedText,
      segments: segments.map(s => ({ text: s, status: 'idle' }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const stopAudio = useCallback(() => {
    if (currentSourceRef.current) {
      currentSourceRef.current.stop();
      currentSourceRef.current = null;
    }
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const playSegment = useCallback(async (index: number) => {
    if (!story) return;

    const ctx = getAudioContext();
    stopAudio();

    const segment = story.segments[index];
    let audioBuffer = segment.audioBuffer;

    if (!audioBuffer) {
      // Update status to generating
      setStory(prev => {
        if (!prev) return null;
        const newSegments = [...prev.segments];
        newSegments[index].status = 'generating';
        return { ...prev, segments: newSegments };
      });

      try {
        audioBuffer = await generateSpeech(segment.text, playback.voice, ctx);

        // Save buffer
        setStory(prev => {
          if (!prev) return null;
          const newSegments = [...prev.segments];
          newSegments[index].audioBuffer = audioBuffer;
          newSegments[index].status = 'ready';
          return { ...prev, segments: newSegments };
        });
      } catch (err: any) {
        setError("Error generating speech: " + err.message);
        setStory(prev => {
          if (!prev) return null;
          const newSegments = [...prev.segments];
          newSegments[index].status = 'error';
          return { ...prev, segments: newSegments };
        });
        return;
      }
    }

    if (audioBuffer) {
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => {
        // Auto-advance to next segment
        if (index + 1 < story.segments.length) {
          setPlayback(prev => {
             if (prev.isPlaying && prev.currentSegmentIndex === index) {
                return { ...prev, currentSegmentIndex: index + 1 };
             }
             return prev;
          });
        } else {
          setPlayback(prev => ({ ...prev, isPlaying: false }));
        }
      };

      currentSourceRef.current = source;
      source.start();
      setPlayback(prev => ({ ...prev, currentSegmentIndex: index, isPlaying: true }));
    }
  }, [story, playback.voice, stopAudio]);

  // Effect to trigger playback when segment index changes automatically
  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying, story, playSegment]);

  const togglePlay = () => {
    if (playback.isPlaying) {
      stopAudio();
    } else {
      playSegment(playback.currentSegmentIndex);
    }
  };

  const skip = (direction: 'prev' | 'next') => {
    if (!story) return;
    const newIdx = direction === 'next' 
      ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1)
      : Math.max(playback.currentSegmentIndex - 1, 0);

    if (newIdx !== playback.currentSegmentIndex) {
      setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col">
      {/* Header */}
      <header className="border-b border-stone-200 bg-white/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-amber-500 rounded-lg flex items-center justify-center text-white">
              <BookOpen size={20} />
            </div>
            <span className="font-bold text-xl tracking-tight text-stone-800">KittenStory</span>
          </div>

          {story && (
            <button 
              onClick={() => {
                stopAudio();
                setStory(null);
                setPlayback(p => ({ ...p, isPlaying: false, currentSegmentIndex: 0 }));
              }}
              className="text-stone-400 hover:text-stone-600 p-2"
            >
              <X size={24} />
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        {error && (
          <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] w-full max-w-md px-4">
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg flex items-start gap-3 shadow-lg">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1 text-sm">{error}</div>
              <button onClick={() => setError(null)} className="shrink-0"><X size={16} /></button>
            </div>
          </div>
        )}

        {!story ? (
          <div className="max-w-2xl mx-auto px-6 py-20 flex flex-col items-center">
            <div className="text-center mb-12">
              <h2 className="serif text-4xl font-bold text-stone-800 mb-4">Your stories, read aloud.</h2>
              <p className="text-stone-500 text-lg">Upload a document or paste a story to start listening with high-quality AI voices.</p>
            </div>

            <div className="w-full grid md:grid-cols-2 gap-6">
              {/* File Upload Box */}
              <label className="group relative border-2 border-dashed border-stone-300 rounded-2xl p-10 flex flex-col items-center gap-4 hover:border-amber-400 hover:bg-amber-50/30 transition-all cursor-pointer">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={handleFileUpload} />
                <div className="w-16 h-16 rounded-full bg-stone-100 group-hover:bg-amber-100 flex items-center justify-center text-stone-400 group-hover:text-amber-500 transition-colors">
                  <Upload size={32} />
                </div>
                <div className="text-center">
                  <p className="font-semibold text-stone-700">Upload Document</p>
                  <p className="text-sm text-stone-400">PDF, DOCX, or TXT</p>
                </div>
              </label>

              {/* Paste Text Box */}
              <div className="flex flex-col gap-3">
                <textarea 
                  placeholder="...or paste your story text here"
                  className="w-full h-40 p-4 border border-stone-300 rounded-2xl focus:ring-2 focus:ring-amber-500 focus:border-transparent outline-none resize-none bg-white text-stone-700 text-sm"
                  value={pastedText}
                  onChange={(e) => setPastedText(e.target.value)}
                />
                <button 
                  onClick={handlePastedStory}
                  disabled={!pastedText.trim()}
                  className="w-full py-4 bg-stone-800 text-white rounded-2xl font-semibold hover:bg-stone-900 disabled:opacity-50 transition-all flex items-center justify-center gap-2"
                >
                  <FileText size={20} />
                  Start Reading
                </button>
              </div>
            </div>

            <div className="mt-20 text-center">
              <p className="text-stone-400 text-sm uppercase tracking-widest font-bold mb-4">Powered by</p>
              <div className="flex gap-8 items-center justify-center opacity-50 grayscale">
                <span className="font-bold text-lg">Gemini 2.5 TTS</span>
                <span className="font-bold text-lg">Kitten Engine</span>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            onTogglePlay={togglePlay}
            onSkip={skip}
            onVoiceChange={(v) => {
              stopAudio();
              setPlayback(p => ({ ...p, voice: v, isPlaying: false }));
            }}
            onSegmentClick={(idx) => {
              setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }));
            }}
          />
        )}
      </main>
    </div>
  );
};

export default App;

