  story: Story;
  playback: PlaybackState;
  onTogglePlay: () => void;
  onSkip: (direction: 'prev' | 'next') => void;
  onVoiceChange: (voice: VoiceName) => void;
  onEngineChange: (engine: ReaderEngine) => void;
  onSegmentClick: (index: number) => void;
}

const Reader: React.FC<ReaderProps> = ({ 
  story, 
  playback, 
  onTogglePlay, 
  onSkip, 
  onVoiceChange,
  onEngineChange,
  onSegmentClick 
}) => {
  const activeSegmentRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (activeSegmentRef.current) {
      activeSegmentRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [playback.currentSegmentIndex]);

  return (
    <div className="max-w-4xl mx-auto h-full flex flex-col">
      <div className="flex-1 overflow-y-auto px-6 py-12 hide-scrollbar">
        <h1 className="serif text-4xl md:text-5xl font-bold mb-4 text-stone-800 text-center">
          {story.title}
