            >
              <div className="flex items-start gap-4">
                <span className={`text-xs mt-2 shrink-0 font-mono ${idx === playback.currentSegmentIndex ? 'text-amber-500' : 'text-stone-300'}`}>
                  {(idx + 1).toString().padStart(2, '0')}
                </span>
