declare const pdfjsLib: any;
declare const mammoth: any;

// Initialize PDF.js worker
if (typeof pdfjsLib !== 'undefined') {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

export const parseFile = async (file: File): Promise<string> => {
  const extension = file.name.split('.').pop()?.toLowerCase();

  if (extension === 'txt') {
    return await file.text();
  } 

  if (extension === 'pdf') {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = "";
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const content = await page.getTextContent();
      const strings = content.items.map((item: any) => item.str);
      fullText += strings.join(" ") + "\n";
    }
    return fullText;
  }

  if (extension === 'docx') {
    const arrayBuffer = await file.arrayBuffer();
    const result = await mammoth.extractRawText({ arrayBuffer });
    return result.value;
  }

  throw new Error("Unsupported file format. Please upload PDF, DOCX, or TXT.");
};

export const segmentText = (text: string): string[] => {
  // Split by double newlines or punctuation for natural reading segments
  return text
    .split(/\n\s*\n|\.|\?|!/)
    .map(s => s.trim())
    .filter(s => s.length > 5);
};

import { GoogleGenAI, Modality } from "@google/genai";
import { VoiceName } from "../types";

// Manual implementation of decode function as per guidelines
export function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Custom function to decode raw PCM data returned by Gemini TTS
export async function decodeRawPCM(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const generateSpeech = async (
  text: string, 
  voice: VoiceName, 
  audioContext: AudioContext
): Promise<{ buffer: AudioBuffer, raw: Uint8Array }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Read this story segment naturally: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voice },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("No audio data received from Gemini API");
  }

  const raw = decodeBase64(base64Audio);
  const buffer = await decodeRawPCM(raw, audioContext, 24000, 1);

  return { buffer, raw };
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, BookOpen, FileText, X, AlertCircle, Sparkles, Zap, User } from 'lucide-react';
import { Story, PlaybackState, VoiceName, ReaderEngine, StorySegment } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import { generateSpeech, decodeRawPCM } from './services/geminiService';
import { audioCache } from './utils/storage';
import Reader from './components/Reader';

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voice: VoiceName.Kore,
    engine: ReaderEngine.CLOUD,
    speed: 1.0
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const synthRef = useRef<SpeechSynthesis | null>(window.speechSynthesis);

  const getAudioContext = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return audioContextRef.current;
  }, []);

  const stopAudio = useCallback(() => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.stop();
      } catch (e) {
        // Ignore if already stopped
      }
      currentSourceRef.current = null;
    }
    if (synthRef.current) {
      synthRef.current.cancel();
    }
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const createStory = (title: string, text: string) => {
    const segments = segmentText(text);
    const storyId = btoa(title + text.slice(0, 20)).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ 
        id: `${storyId}-${idx}`,
        text: s, 
        status: 'idle' 
      }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const playSegment = useCallback(async (index: number) => {
    if (!story) return;
    stopAudio();

    const segment = story.segments[index];
    const ctx = getAudioContext();

    // Ensure AudioContext is running (browsers suspend it)
    if (ctx.state === 'suspended') {
      await ctx.resume();
    }

    if (playback.engine === ReaderEngine.LOCAL) {
      const utter = new SpeechSynthesisUtterance(segment.text);
      utter.rate = playback.speed;
      utter.onend = () => {
        setPlayback(prev => {
          if (prev.isPlaying && index + 1 < story.segments.length) {
            return { ...prev, currentSegmentIndex: index + 1 };
          }
          return { ...prev, isPlaying: false };
        });
      };
      synthRef.current?.speak(utter);
      setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
      return;
    }

    // CLOUD ENGINE WITH CACHING
    let audioBuffer = segment.audioBuffer;

    if (!audioBuffer) {
      const cachedData = await audioCache.get(segment.id);
      if (cachedData) {
        // Raw PCM needs custom decoding
        audioBuffer = await decodeRawPCM(new Uint8Array(cachedData), ctx, 24000, 1);
      } else {
        setStory(prev => {
          if (!prev) return null;
          const newSegments = [...prev.segments];
          newSegments[index].status = 'generating';
          return { ...prev, segments: newSegments };
        });

        try {
          const result = await generateSpeech(segment.text, playback.voice, ctx);
          audioBuffer = result.buffer;
          // Persist to local cache for offline/reuse
          await audioCache.set(segment.id, result.raw.buffer);
        } catch (err: any) {
          setError(err.message || "Failed to generate speech");
          setPlayback(p => ({ ...p, isPlaying: false }));
          return;
        }
      }
    }

    if (audioBuffer) {
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.playbackRate.value = playback.speed;
      source.connect(ctx.destination);
      source.onended = () => {
        setPlayback(prev => {
          if (prev.isPlaying && index + 1 < story.segments.length) {
            return { ...prev, currentSegmentIndex: index + 1 };
          }
          return { ...prev, isPlaying: false };
        });
      };
      currentSourceRef.current = source;
      source.start();
      setPlayback(prev => ({ ...prev, currentSegmentIndex: index, isPlaying: true }));

      setStory(prev => {
        if (!prev) return null;
        const newSegments = [...prev.segments];
        newSegments[index].audioBuffer = audioBuffer;
        newSegments[index].status = 'cached';
        return { ...prev, segments: newSegments };
      });
    }
  }, [story, playback.voice, playback.engine, playback.speed, stopAudio, getAudioContext]);

  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying]);

  useEffect(() => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.playbackRate.setTargetAtTime(playback.speed, getAudioContext().currentTime, 0.1);
      } catch (e) {
        // Fallback for older contexts
        currentSourceRef.current.playbackRate.value = playback.speed;
      }
    }
  }, [playback.speed, getAudioContext]);

  return (
    <div className="min-h-screen bg-[#FFF9F2] flex flex-col selection:bg-amber-100 selection:text-amber-900">
      <header className="border-b border-amber-100/50 bg-white/70 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-amber-400 to-orange-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-100">
              <Sparkles size={22} />
            </div>
            <div>
              <span className="font-black text-xl tracking-tight text-stone-800 block leading-none">KittenReader</span>
              <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Ultra Lightweight TTS</span>
            </div>
          </div>

          {story && (
            <button 
              onClick={() => { stopAudio(); setStory(null); }}
              className="w-10 h-10 flex items-center justify-center text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
            >
              <X size={24} />
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        {error && (
          <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] w-full max-w-md px-4 animate-in fade-in slide-in-from-top-4">
            <div className="bg-red-50 border border-red-100 text-red-700 px-4 py-3 rounded-2xl flex items-start gap-3 shadow-xl">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1 text-sm font-medium">{error}</div>
              <button onClick={() => setError(null)} className="shrink-0 opacity-50 hover:opacity-100"><X size={16} /></button>
            </div>
          </div>
        )}

        {!story ? (
          <div className="max-w-4xl mx-auto px-6 py-12 md:py-20">
            <div className="text-center mb-12">
              <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-amber-100 text-amber-700 text-xs font-bold uppercase tracking-widest mb-6">
                <Zap size={14} /> Inspired by Kitten TTS
              </div>
              <h2 className="serif text-5xl md:text-7xl font-bold text-stone-800 mb-6 leading-tight">
                Reading made <br/><span className="text-amber-500 italic">effortless.</span>
              </h2>
              <p className="text-stone-500 text-xl max-w-2xl mx-auto font-medium">
                The lightweight offline-ready story reader. Select a voice and bring your documents to life.
              </p>
            </div>

            <div className="mb-16">
              <p className="text-center text-stone-400 text-xs font-bold uppercase tracking-[0.2em] mb-6 flex items-center justify-center gap-2">
                <User size={14} /> Select Your Narrator
              </p>
              <div className="flex flex-wrap justify-center gap-4">
                {Object.values(VoiceName).map(v => (
                  <button
                    key={v}
                    onClick={() => setPlayback(p => ({ ...p, voice: v }))}
                    className={`
                      px-6 py-4 rounded-[1.5rem] font-bold transition-all border-2 text-sm flex items-center gap-2
                      ${playback.voice === v 
                        ? 'bg-amber-500 border-amber-500 text-white shadow-xl shadow-amber-200 scale-105' 
                        : 'bg-white border-amber-100 text-stone-600 hover:border-amber-300 hover:shadow-md'
                      }
                    `}
                  >
                    <div className={`w-2 h-2 rounded-full ${playback.voice === v ? 'bg-white' : 'bg-amber-300'}`} />
                    {v}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
              <label className="group relative bg-white border-2 border-dashed border-amber-200 rounded-[2.5rem] p-12 flex flex-col items-center gap-6 hover:border-amber-400 hover:bg-white transition-all cursor-pointer shadow-sm hover:shadow-2xl hover:-translate-y-1">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                   const file = e.target.files?.[0];
                   if (file) {
                     setError(null);
                     try {
                       const text = await parseFile(file);
                       createStory(file.name.split('.')[0], text);
                     } catch (err: any) { setError(err.message); }
                   }
                }} />
                <div className="w-20 h-20 rounded-3xl bg-amber-50 group-hover:bg-amber-500 flex items-center justify-center text-amber-500 group-hover:text-white transition-all duration-500">
                  <Upload size={36} />
                </div>
                <div className="text-center">
                  <p className="font-bold text-xl text-stone-800 mb-1">Upload Script</p>
                  <p className="text-sm font-medium text-stone-400">PDF, Word, or Text files</p>
                </div>
              </label>

              <div className="flex flex-col gap-4">
                <textarea 
                  placeholder="Or drop your words here..."
                  className="w-full h-48 p-6 bg-white border border-amber-100 rounded-[2.5rem] focus:ring-4 focus:ring-amber-500/10 focus:border-amber-400 outline-none resize-none text-stone-700 text-lg serif shadow-sm transition-all"
                  value={pastedText}
                  onChange={(e) => setPastedText(e.target.value)}
                />
                <button 
                  onClick={() => createStory("New Adventure", pastedText)}
                  disabled={!pastedText.trim()}
                  className="w-full py-5 bg-stone-900 text-white rounded-[2rem] font-bold text-lg hover:bg-amber-500 hover:shadow-xl hover:shadow-amber-200 disabled:opacity-30 transition-all flex items-center justify-center gap-3"
                >
                  <FileText size={22} />
                  Start Listening
                </button>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(v) => { stopAudio(); setPlayback(p => ({ ...p, voice: v, isPlaying: false })); }}
            onEngineChange={(e) => { stopAudio(); setPlayback(p => ({ ...p, engine: e, isPlaying: false })); }}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

