        setStory(prev => {
          if (!prev) return null;
          const newSegments = [...prev.segments];
          newSegments[i].status = 'generating';
          return { ...prev, segments: newSegments };
        });

        try {
          const result = await generateSpeech(segment.text, playback.voice, ctx);
          await audioCache.set(segment.id, result.raw.buffer);

          setStory(prev => {
            if (!prev) return null;
            const newSegments = [...prev.segments];
            newSegments[i].audioBuffer = result.buffer;
            newSegments[i].status = 'cached';
            return { ...prev, segments: newSegments };
          });
        } catch (err: any) {
          console.error(`Failed to cache segment ${i}:`, err);
        }
      } else if (story.segments[i].status !== 'cached') {
        const buffer = await decodeRawPCM(new Uint8Array(cachedData), ctx, 24000, 1);
        setStory(prev => {
          if (!prev) return null;
          const newSegments = [...prev.segments];
          newSegments[i].audioBuffer = buffer;
          newSegments[i].status = 'cached';
          return { ...prev, segments: newSegments };
        });
      }
      setCacheProgress(Math.round(((i + 1) / story.segments.length) * 100));
    }
    setIsCachingAll(false);
  };

  const playSegment = useCallback(async (index: number) => {
    if (!story) return;
    stopAudio();

    const segment = story.segments[index];
    const ctx = getAudioContext();

    if (ctx.state === 'suspended') {
      await ctx.resume();
    }

    if (playback.engine === ReaderEngine.LOCAL) {
      const utter = new SpeechSynthesisUtterance(segment.text);
      utter.rate = playback.speed;
      // Local engine fallback uses the system default or Kitten-style lightweight synthesis
      utter.onend = () => {
        setPlayback(prev => {
          if (prev.isPlaying && index + 1 < story.segments.length) {
            return { ...prev, currentSegmentIndex: index + 1 };
          }
          return { ...prev, isPlaying: false };
        });
      };
      synthRef.current?.speak(utter);
      setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
      return;
    }

    let audioBuffer = segment.audioBuffer;

    if (!audioBuffer) {
      const cachedData = await audioCache.get(segment.id);
      if (cachedData) {
        audioBuffer = await decodeRawPCM(new Uint8Array(cachedData), ctx, 24000, 1);
      } else {
        setStory(prev => {
          if (!prev) return null;
          const newSegments = [...prev.segments];
          newSegments[index].status = 'generating';
          return { ...prev, segments: newSegments };
        });

        try {
          const result = await generateSpeech(segment.text, playback.voice, ctx);
          audioBuffer = result.buffer;
          await audioCache.set(segment.id, result.raw.buffer);
        } catch (err: any) {
          setError(err.message || "Failed to generate speech");
          setPlayback(p => ({ ...p, isPlaying: false }));
          return;
        }
      }
    }

    if (audioBuffer) {
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.playbackRate.value = playback.speed;
      source.connect(ctx.destination);
      source.onended = () => {
        setPlayback(prev => {
          if (prev.isPlaying && index + 1 < story.segments.length) {
            return { ...prev, currentSegmentIndex: index + 1 };
          }
          return { ...prev, isPlaying: false };
        });
      };
      currentSourceRef.current = source;
      source.start();
      setPlayback(prev => ({ ...prev, currentSegmentIndex: index, isPlaying: true }));

      setStory(prev => {
        if (!prev) return null;
        const newSegments = [...prev.segments];
        newSegments[index].audioBuffer = audioBuffer;
        newSegments[index].status = 'cached';
        return { ...prev, segments: newSegments };
      });
    }
  }, [story, playback.voice, playback.engine, playback.speed, stopAudio, getAudioContext]);

  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying]);

  useEffect(() => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.playbackRate.setTargetAtTime(playback.speed, getAudioContext().currentTime, 0.1);
      } catch (e) {
        currentSourceRef.current.playbackRate.value = playback.speed;
      }
    }
  }, [playback.speed, getAudioContext]);

  return (
    <div className="min-h-screen bg-[#FFF9F2] flex flex-col selection:bg-amber-100 selection:text-amber-900">
      <header className="border-b border-amber-100/50 bg-white/70 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-amber-400 to-orange-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-100">
              <Sparkles size={22} />
            </div>
            <div>
              <span className="font-black text-xl tracking-tight text-stone-800 block leading-none">KittenReader</span>
              <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Ultra Lightweight TTS</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {story && !isCachingAll && cacheProgress < 100 && (
              <button 
                onClick={cacheAllSegments}
                className="flex items-center gap-2 px-4 py-2 bg-amber-50 text-amber-700 rounded-xl text-xs font-bold hover:bg-amber-100 transition-colors"
              >
                <Download size={14} /> Make Offline
              </button>
            )}
            {cacheProgress === 100 && (
               <div className="flex items-center gap-2 px-4 py-2 bg-green-50 text-green-700 rounded-xl text-xs font-bold">
                 <CheckCircle2 size={14} /> Ready Offline
               </div>
            )}
            {isCachingAll && (
               <div className="flex items-center gap-3 px-4 py-2 bg-amber-50 rounded-xl">
                 <div className="w-24 h-1.5 bg-amber-200 rounded-full overflow-hidden">
                    <div className="h-full bg-amber-500 transition-all duration-300" style={{ width: `${cacheProgress}%` }} />
                 </div>
                 <span className="text-[10px] font-bold text-amber-700">{cacheProgress}%</span>
               </div>
            )}
            {story && (
              <button 
                onClick={() => { stopAudio(); setStory(null); }}
                className="w-10 h-10 flex items-center justify-center text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
              >
                <X size={24} />
              </button>
            )}
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        {error && (
          <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] w-full max-w-md px-4 animate-in fade-in slide-in-from-top-4">
            <div className="bg-red-50 border border-red-100 text-red-700 px-4 py-3 rounded-2xl flex items-start gap-3 shadow-xl">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1 text-sm font-medium">{error}</div>
              <button onClick={() => setError(null)} className="shrink-0 opacity-50 hover:opacity-100"><X size={16} /></button>
            </div>
          </div>
        )}

        {!story ? (
          <div className="max-w-4xl mx-auto px-6 py-12 md:py-20">
            <div className="text-center mb-12">
              <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-amber-100 text-amber-700 text-xs font-bold uppercase tracking-widest mb-6">
                <Zap size={14} /> Local-First Architecture
              </div>
              <h2 className="serif text-5xl md:text-7xl font-bold text-stone-800 mb-6 leading-tight">
                Reading made <br/><span className="text-amber-500 italic">effortless.</span>
              </h2>
              <p className="text-stone-500 text-xl max-w-2xl mx-auto font-medium">
                KittenReader transforms your stories with local-first synthesis. Save once, listen anywhere—even offline.
              </p>
            </div>

            <div className="mb-16">
              <p className="text-center text-stone-400 text-xs font-bold uppercase tracking-[0.2em] mb-6 flex items-center justify-center gap-2">
                <User size={14} /> Select Your Narrator
              </p>
              <div className="flex flex-wrap justify-center gap-4">
                {Object.values(VoiceName).map(v => (
                  <button
                    key={v}
                    onClick={() => setPlayback(p => ({ ...p, voice: v }))}
                    className={`
                      px-6 py-4 rounded-[1.5rem] font-bold transition-all border-2 text-sm flex items-center gap-2
                      ${playback.voice === v 
                        ? 'bg-amber-500 border-amber-500 text-white shadow-xl shadow-amber-200 scale-105' 
                        : 'bg-white border-amber-100 text-stone-600 hover:border-amber-300 hover:shadow-md'
                      }
                    `}
                  >
                    <div className={`w-2 h-2 rounded-full ${playback.voice === v ? 'bg-white' : 'bg-amber-300'}`} />
                    {v}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
              <label className="group relative bg-white border-2 border-dashed border-amber-200 rounded-[2.5rem] p-12 flex flex-col items-center gap-6 hover:border-amber-400 hover:bg-white transition-all cursor-pointer shadow-sm hover:shadow-2xl hover:-translate-y-1">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                   const file = e.target.files?.[0];
                   if (file) {
                     setError(null);
                     try {
                       const text = await parseFile(file);
                       createStory(file.name.split('.')[0], text);
                     } catch (err: any) { setError(err.message); }
                   }
                }} />
                <div className="w-20 h-20 rounded-3xl bg-amber-50 group-hover:bg-amber-500 flex items-center justify-center text-amber-500 group-hover:text-white transition-all duration-500">
                  <Upload size={36} />
                </div>
                <div className="text-center">
                  <p className="font-bold text-xl text-stone-800 mb-1">Upload Script</p>
                  <p className="text-sm font-medium text-stone-400">PDF, Word, or Text files</p>
                </div>
              </label>

              <div className="flex flex-col gap-4">
                <textarea 
                  placeholder="Or drop your words here..."
                  className="w-full h-48 p-6 bg-white border border-amber-100 rounded-[2.5rem] focus:ring-4 focus:ring-amber-500/10 focus:border-amber-400 outline-none resize-none text-stone-700 text-lg serif shadow-sm transition-all"
                  value={pastedText}
                  onChange={(e) => setPastedText(e.target.value)}
                />
                <button 
                  onClick={() => createStory("New Adventure", pastedText)}
                  disabled={!pastedText.trim()}
                  className="w-full py-5 bg-stone-900 text-white rounded-[2rem] font-bold text-lg hover:bg-amber-500 hover:shadow-xl hover:shadow-amber-200 disabled:opacity-30 transition-all flex items-center justify-center gap-3"
                >
                  <FileText size={22} />
                  Start Listening
                </button>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(v) => { stopAudio(); setPlayback(p => ({ ...p, voice: v, isPlaying: false })); }}
            onEngineChange={(e) => { stopAudio(); setPlayback(p => ({ ...p, engine: e, isPlaying: false })); }}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Settings, Zap, WifiOff, Cloud, Gauge } from 'lucide-react';
import { Story, PlaybackState, VoiceName, ReaderEngine } from '../types';

interface ReaderProps {
  story: Story;
  playback: PlaybackState;
  onTogglePlay: () => void;
  onSkip: (direction: 'prev' | 'next') => void;
  onVoiceChange: (voice: VoiceName) => void;
  onEngineChange: (engine: ReaderEngine) => void;
  onSpeedChange: (speed: number) => void;
  onSegmentClick: (index: number) => void;
}

const Reader: React.FC<ReaderProps> = ({ 
  story, 
  playback, 
  onTogglePlay, 
  onSkip, 
  onVoiceChange,
  onEngineChange,
  onSpeedChange,
  onSegmentClick 
}) => {
  const activeSegmentRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (activeSegmentRef.current) {
      activeSegmentRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [playback.currentSegmentIndex]);

  return (
    <div className="max-w-4xl mx-auto h-full flex flex-col">
      <div className="flex-1 overflow-y-auto px-6 py-12 hide-scrollbar">
        <h1 className="serif text-4xl md:text-5xl font-bold mb-4 text-stone-800 text-center">
          {story.title}
        </h1>
        <div className="flex justify-center items-center gap-4 mb-12">
           <span className={`text-xs px-3 py-1 rounded-full font-bold uppercase tracking-widest ${playback.engine === ReaderEngine.CLOUD ? 'bg-amber-100 text-amber-700 shadow-sm' : 'bg-green-100 text-green-700 shadow-sm'}`}>
             {playback.engine}
           </span>
           {playback.engine === ReaderEngine.LOCAL && (
             <span className="text-[10px] font-bold text-stone-400 uppercase tracking-tighter">Native Synthesis Active</span>
           )}
        </div>

        <div className="space-y-4">
          {story.segments.map((segment, idx) => (
            <div 
              key={idx}
              ref={idx === playback.currentSegmentIndex ? activeSegmentRef : null}
              onClick={() => onSegmentClick(idx)}
              className={`
                group relative p-6 rounded-2xl transition-all duration-300 cursor-pointer text-xl leading-relaxed serif border-2
                ${idx === playback.currentSegmentIndex 
                  ? 'bg-white border-amber-300 text-stone-900 shadow-xl scale-[1.02] z-10' 
                  : 'border-transparent text-stone-400 hover:text-stone-600 hover:bg-white/50'}
              `}
            >
              <div className="flex items-start gap-4">
                <span className={`text-xs mt-2 shrink-0 font-mono ${idx === playback.currentSegmentIndex ? 'text-amber-500' : 'text-stone-300'}`}>
                  {(idx + 1).toString().padStart(2, '0')}
                </span>
                <span className="flex-1">{segment.text}</span>
                <div className="shrink-0 flex items-center gap-2">
                   {segment.status === 'cached' && <Zap size={14} className="text-green-500" title="Offline Ready" />}
                   {segment.status === 'generating' && (
                     <div className="flex gap-1">
                        <div className="w-1 h-1 bg-amber-400 rounded-full animate-bounce"></div>
                        <div className="w-1 h-1 bg-amber-400 rounded-full animate-bounce [animation-delay:0.1s]"></div>
                        <div className="w-1 h-1 bg-amber-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                     </div>
                   )}
                </div>
              </div>
            </div>
          ))}
        </div>
        <div className="h-60" />
      </div>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-50">
        <div className="bg-white/95 backdrop-blur-xl border border-amber-100 shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-5 flex flex-col md:flex-row items-center justify-between gap-6 md:gap-4">

          <div className="flex items-center gap-3">
            <button onClick={() => onSkip('prev')} className="p-2 text-stone-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-colors">
              <SkipBack size={24} />
            </button>
            <button 
              onClick={onTogglePlay}
              className="w-16 h-16 bg-amber-500 hover:bg-amber-600 text-white rounded-full flex items-center justify-center shadow-lg shadow-amber-200 transition-all hover:scale-105 active:scale-95"
            >
              {playback.isPlaying ? <Pause size={32} /> : <Play size={32} fill="currentColor" className="ml-1" />}
            </button>
            <button onClick={() => onSkip('next')} className="p-2 text-stone-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-colors">
              <SkipForward size={24} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center gap-2 w-full max-w-xs">
            <div className="flex items-center justify-between w-full px-2">
              <div className="flex items-center gap-2 text-stone-400">
                <Gauge size={14} />
                <span className="text-[10px] font-bold uppercase tracking-wider">Speed</span>
              </div>
              <span className="text-sm font-bold text-amber-600">{playback.speed.toFixed(1)}x</span>
            </div>
            <input 
              type="range" 
              min="0.5" 
              max="2.0" 
              step="0.1" 
              value={playback.speed}
              onChange={(e) => onSpeedChange(parseFloat(e.target.value))}
              className="w-full h-2 bg-stone-100 rounded-lg appearance-none cursor-pointer accent-amber-500 hover:accent-amber-600 transition-all"
            />
          </div>

          <div className="flex items-center gap-3">
            <div className="flex items-center gap-1 bg-stone-50 p-1 rounded-xl border border-stone-100">
              <button 
                title="Kitten Local (Native synthesis)"
                onClick={() => onEngineChange(ReaderEngine.LOCAL)}
                className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold transition-all ${playback.engine === ReaderEngine.LOCAL ? 'bg-white shadow-sm text-amber-600' : 'text-stone-400'}`}
              >
                <WifiOff size={14} />
              </button>
              <button 
                title="Kitten HD (Gemini synthesis)"
                onClick={() => onEngineChange(ReaderEngine.CLOUD)}
                className={`flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold transition-all ${playback.engine === ReaderEngine.CLOUD ? 'bg-white shadow-sm text-amber-600' : 'text-stone-400'}`}
              >
                <Cloud size={14} />
              </button>
            </div>

            <div className="relative group">
              <button className="flex items-center gap-2 p-3 text-stone-600 hover:bg-stone-50 rounded-2xl border border-transparent hover:border-stone-200 transition-all">
                <Settings size={20} className="text-stone-400" />
                <span className="text-sm font-semibold hidden lg:inline">{playback.voice}</span>
              </button>
              <div className="absolute bottom-full right-0 mb-4 w-40 bg-white border border-amber-100 shadow-2xl rounded-2xl overflow-hidden hidden group-hover:block animate-in fade-in slide-in-from-bottom-2">
                <div className="p-2 text-[10px] uppercase tracking-widest font-bold text-stone-400 border-b border-stone-50">Narrator</div>
                {Object.values(VoiceName).map(v => (
                  <button
                    key={v}
                    onClick={() => onVoiceChange(v)}
                    className={`w-full text-left px-4 py-3 text-sm transition-colors hover:bg-amber-50 ${playback.voice === v ? 'text-amber-600 bg-amber-50/50 font-bold' : 'text-stone-600'}`}
                  >
                    {v}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reader;

export interface StorySegment {
  text: string;
  status: 'idle' | 'ready' | 'error';
  id: string;
}

export interface Story {
  id: string;
  title: string;
  content: string;
  segments: StorySegment[];
}

export interface PlaybackState {
  currentSegmentIndex: number;
  isPlaying: boolean;
  isLoading: boolean;
  voiceURI: string;
  speed: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, Zap, User, FileText } from 'lucide-react';
import { Story, PlaybackState, StorySegment } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');

  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  // Load available system voices
  const updateVoices = useCallback(() => {
    const availableVoices = synthRef.current.getVoices();
    setVoices(availableVoices);
    if (availableVoices.length > 0 && !playback.voiceURI) {
      // Prefer a high-quality or English voice if available
      const defaultVoice = availableVoices.find(v => v.lang.startsWith('en')) || availableVoices[0];
      setPlayback(p => ({ ...p, voiceURI: defaultVoice.voiceURI }));
    }
  }, [playback.voiceURI]);

  useEffect(() => {
    updateVoices();
    if (synthRef.current.onvoiceschanged !== undefined) {
      synthRef.current.onvoiceschanged = updateVoices;
    }
  }, [updateVoices]);

  const stopAudio = useCallback(() => {
    synthRef.current.cancel();
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const createStory = (title: string, text: string) => {
    const segments = segmentText(text);
    const storyId = btoa(title + text.slice(0, 20)).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ 
        id: `${storyId}-${idx}`,
        text: s, 
        status: 'idle' 
      }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const playSegment = useCallback((index: number) => {
    if (!story) return;
    stopAudio();

    const segment = story.segments[index];
    const utter = new SpeechSynthesisUtterance(segment.text);

    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;

    utter.rate = playback.speed;
    utter.onend = () => {
      setPlayback(prev => {
        if (prev.isPlaying && index + 1 < story.segments.length) {
          return { ...prev, currentSegmentIndex: index + 1 };
        }
        return { ...prev, isPlaying: false };
      });
    };
    utter.onerror = (e) => {
      console.error("SpeechSynthesis error:", e);
      setError("Playback error. Your browser might not support this voice.");
      setPlayback(p => ({ ...p, isPlaying: false }));
    };

    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying]);

  return (
    <div className="min-h-screen bg-[#FFF9F2] flex flex-col selection:bg-amber-100 selection:text-amber-900">
      <header className="border-b border-amber-100/50 bg-white/70 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-amber-400 to-orange-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-100">
              <Sparkles size={22} />
            </div>
            <div>
              <span className="font-black text-xl tracking-tight text-stone-800 block leading-none">KittenReader</span>
              <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Pure Offline Reader</span>
            </div>
          </div>

          {story && (
            <button 
              onClick={() => { stopAudio(); setStory(null); }}
              className="w-10 h-10 flex items-center justify-center text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
            >
              <X size={24} />
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        {error && (
          <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] w-full max-w-md px-4 animate-in fade-in slide-in-from-top-4">
