              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1 text-sm font-medium">{error}</div>
              <button onClick={() => setError(null)} className="shrink-0 opacity-50 hover:opacity-100"><X size={16} /></button>
            </div>
          </div>
        )}

        {!story ? (
          <div className="max-w-4xl mx-auto px-6 py-12 md:py-20">
            <div className="text-center mb-12">
              <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-amber-100 text-amber-700 text-xs font-bold uppercase tracking-widest mb-6">
                <Zap size={14} /> 100% Offline Logic
              </div>
              <h2 className="serif text-5xl md:text-7xl font-bold text-stone-800 mb-6 leading-tight">
                Your stories, <br/><span className="text-amber-500 italic">anywhere.</span>
              </h2>
              <p className="text-stone-500 text-xl max-w-2xl mx-auto font-medium">
                No internet? No problem. KittenReader uses your device's native hardware for lightning-fast, private storytelling.
              </p>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
              <label className="group relative bg-white border-2 border-dashed border-amber-200 rounded-[2.5rem] p-12 flex flex-col items-center gap-6 hover:border-amber-400 hover:bg-white transition-all cursor-pointer shadow-sm hover:shadow-2xl hover:-translate-y-1">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                   const file = e.target.files?.[0];
                   if (file) {
                     setError(null);
                     try {
                       const text = await parseFile(file);
                       createStory(file.name.split('.')[0], text);
                     } catch (err: any) { setError(err.message); }
                   }
                }} />
                <div className="w-20 h-20 rounded-3xl bg-amber-50 group-hover:bg-amber-500 flex items-center justify-center text-amber-500 group-hover:text-white transition-all duration-500">
                  <Upload size={36} />
                </div>
                <div className="text-center">
                  <p className="font-bold text-xl text-stone-800 mb-1">Upload Script</p>
                  <p className="text-sm font-medium text-stone-400">PDF, Word, or Text files</p>
                </div>
              </label>

              <div className="flex flex-col gap-4">
                <textarea 
                  placeholder="Or drop your words here..."
                  className="w-full h-48 p-6 bg-white border border-amber-100 rounded-[2.5rem] focus:ring-4 focus:ring-amber-500/10 focus:border-amber-400 outline-none resize-none text-stone-700 text-lg serif shadow-sm transition-all"
                  value={pastedText}
                  onChange={(e) => setPastedText(e.target.value)}
                />
                <button 
                  onClick={() => createStory("New Adventure", pastedText)}
                  disabled={!pastedText.trim()}
                  className="w-full py-5 bg-stone-900 text-white rounded-[2rem] font-bold text-lg hover:bg-amber-500 hover:shadow-xl hover:shadow-amber-200 disabled:opacity-30 transition-all flex items-center justify-center gap-3"
                >
                  <FileText size={22} />
                  Start Listening
                </button>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            voices={voices}
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

export default App;

