import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, Zap, FileText } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');

  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  // Filter voices: Female voices from English (US/UK/IN) and Spanish (ES)
  const getFilteredVoices = (allVoices: SpeechSynthesisVoice[]) => {
    const allowedLocales = ['en-US', 'en-GB', 'en-IN', 'es-ES'];
    const femaleKeywords = [
      'female', 'woman', 'girl', 'lady', 
      'samantha', 'victoria', 'karen', 'moira', 'tessa', 'kathy', // Apple
      'zira', 'maria', 'hazel', 'monica', 'helena', 'laura', // Microsoft
      'google us english' // Chrome default female
    ];

    return allVoices.filter(v => {
      const isAllowedLocale = allowedLocales.some(locale => 
        v.lang.toLowerCase().replace('_', '-').startsWith(locale.toLowerCase())
      );
      if (!isAllowedLocale) return false;

      const nameLower = v.name.toLowerCase();
      // Check for explicit gender metadata or common female voice names
      return femaleKeywords.some(keyword => nameLower.includes(keyword)) || 
             (v.name.includes('Google') && (v.lang.startsWith('en') || v.lang.startsWith('es')));
    });
  };

  const updateVoices = useCallback(() => {
    const allVoices = synthRef.current.getVoices();
    const filtered = getFilteredVoices(allVoices);

    if (filtered.length > 0) {
      setVoices(filtered);
      setPlayback(p => {
        if (!p.voiceURI) {
          const preferred = 
            filtered.find(v => v.name.includes('Google') && v.lang.startsWith('en-US')) ||
            filtered.find(v => v.lang.startsWith('en')) || 
            filtered[0];
          return { ...p, voiceURI: preferred.voiceURI };
        }
        return p;
      });
    }
  }, []);

  useEffect(() => {
    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') {
      synthRef.current.onvoiceschanged = updateVoices;
    }
    const interval = setInterval(() => {
      if (voices.length === 0) updateVoices();
      else clearInterval(interval);
    }, 1000);
    return () => clearInterval(interval);
  }, [updateVoices, voices.length]);

  const stopAudio = useCallback(() => {
    synthRef.current.cancel();
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const handlePreviewVoice = useCallback((voiceURI: string) => {
    synthRef.current.cancel(); // Interrupt current speech
    const voice = voices.find(v => v.voiceURI === voiceURI);
    if (!voice) return;

    const utter = new SpeechSynthesisUtterance("Testing voice selection.");
    utter.voice = voice;
    utter.rate = playback.speed;
    synthRef.current.speak(utter);
  }, [voices, playback.speed]);

  const createStory = (title: string, text: string) => {
    const segments = segmentText(text);
    const storyId = btoa(title + text.slice(0, 20)).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ 
        id: `${storyId}-${idx}`,
        text: s, 
        status: 'idle' 
      }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const playSegment = useCallback((index: number) => {
    if (!story) return;
    stopAudio();

    const segment = story.segments[index];
    const utter = new SpeechSynthesisUtterance(segment.text);

    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;

    utter.rate = playback.speed;
    utter.onend = () => {
      setPlayback(prev => {
        if (prev.isPlaying && index + 1 < story.segments.length) {
          return { ...prev, currentSegmentIndex: index + 1 };
        }
        return { ...prev, isPlaying: false };
      });
    };
    utter.onerror = (e) => {
      if (e.error !== 'interrupted') {
        setError("Playback error. Voice hardware might be busy.");
        setPlayback(p => ({ ...p, isPlaying: false }));
      }
    };

    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="min-h-screen bg-[#FFF9F2] flex flex-col selection:bg-amber-100 selection:text-amber-900">
      <header className="border-b border-amber-100/50 bg-white/70 backdrop-blur-xl sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-amber-400 to-orange-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-100">
              <Sparkles size={22} />
            </div>
            <div>
              <span className="font-black text-xl tracking-tight text-stone-800 block leading-none">KittenReader</span>
              <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Pure Offline Reader</span>
            </div>
          </div>

          {story && (
            <button 
              onClick={() => { stopAudio(); setStory(null); }}
              className="w-10 h-10 flex items-center justify-center text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
            >
              <X size={24} />
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        {error && (
          <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[60] w-full max-w-md px-4 animate-in fade-in slide-in-from-top-4">
            <div className="bg-red-50 border border-red-100 text-red-700 px-4 py-3 rounded-2xl flex items-start gap-3 shadow-xl">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1 text-sm font-medium">{error}</div>
              <button onClick={() => setError(null)} className="shrink-0 opacity-50 hover:opacity-100"><X size={16} /></button>
            </div>
          </div>
        )}

        {!story ? (
          <div className="max-w-4xl mx-auto px-6 py-12 md:py-20">
            <div className="text-center mb-12">
              <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-amber-100 text-amber-700 text-xs font-bold uppercase tracking-widest mb-6">
                <Zap size={14} /> 100% Offline Logic
              </div>
              <h2 className="serif text-5xl md:text-7xl font-bold text-stone-800 mb-6 leading-tight">
                Your stories, <br/><span className="text-amber-500 italic">anywhere.</span>
              </h2>
              <p className="text-stone-500 text-xl max-w-2xl mx-auto font-medium">
                No internet? No problem. KittenReader uses your device's native hardware for lightning-fast, private storytelling.
              </p>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
              <label className="group relative bg-white border-2 border-dashed border-amber-200 rounded-[2.5rem] p-12 flex flex-col items-center gap-6 hover:border-amber-400 hover:bg-white transition-all cursor-pointer shadow-sm hover:shadow-2xl hover:-translate-y-1">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                   const file = e.target.files?.[0];
                   if (file) {
                     setError(null);
                     try {
                       const text = await parseFile(file);
                       createStory(file.name.split('.')[0], text);
                     } catch (err: any) { setError(err.message); }
                   }
                }} />
                <div className="w-20 h-20 rounded-3xl bg-amber-50 group-hover:bg-amber-500 flex items-center justify-center text-amber-500 group-hover:text-white transition-all duration-500">
                  <Upload size={36} />
                </div>
                <div className="text-center">
                  <p className="font-bold text-xl text-stone-800 mb-1">Upload Script</p>
                  <p className="text-sm font-medium text-stone-400">PDF, Word, or Text files</p>
                </div>
              </label>

              <div className="flex flex-col gap-4">
                <textarea 
                  placeholder="Or drop your words here..."
                  className="w-full h-48 p-6 bg-white border border-amber-100 rounded-[2.5rem] focus:ring-4 focus:ring-amber-500/10 focus:border-amber-400 outline-none resize-none text-stone-700 text-lg serif shadow-sm transition-all"
                  value={pastedText}
                  onChange={(e) => setPastedText(e.target.value)}
                />
                <button 
                  onClick={() => createStory("New Adventure", pastedText)}
                  disabled={!pastedText.trim()}
                  className="w-full py-5 bg-stone-900 text-white rounded-[2rem] font-bold text-lg hover:bg-amber-500 hover:shadow-xl hover:shadow-amber-200 disabled:opacity-30 transition-all flex items-center justify-center gap-3"
                >
                  <FileText size={22} />
                  Start Listening
                </button>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            voices={voices}
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
            onPreviewVoice={handlePreviewVoice}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, Settings, Gauge, User, Check, ChevronUp, Volume2 } from 'lucide-react';
