        <div className="space-y-4">
          {story.segments.map((segment, idx) => (
            <div 
              key={idx}
              ref={idx === playback.currentSegmentIndex ? activeSegmentRef : null}
              onClick={() => onSegmentClick(idx)}
              className={`
                group relative p-6 rounded-2xl transition-all duration-300 cursor-pointer text-xl leading-relaxed serif border-2
                ${idx === playback.currentSegmentIndex 
                  ? 'bg-white border-amber-300 text-stone-900 shadow-xl scale-[1.02] z-10' 
                  : 'border-transparent text-stone-400 hover:text-stone-600 hover:bg-white/50'}
              `}
            >
              <div className="flex items-start gap-4">
                <span className={`text-xs mt-2 shrink-0 font-mono ${idx === playback.currentSegmentIndex ? 'text-amber-500 font-bold' : 'text-stone-300'}`}>
                  {(idx + 1).toString().padStart(2, '0')}
                </span>
                <span className="flex-1">{segment.text}</span>
              </div>
            </div>
          ))}
        </div>
        <div className="h-60" />
      </div>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-50">
        <div className="bg-white/95 backdrop-blur-xl border border-amber-100 shadow-[0_20px_50px_rgba(0,0,0,0.15)] rounded-[2.5rem] p-5 flex flex-col md:flex-row items-center justify-between gap-6 md:gap-4 relative">

          <div className="flex items-center gap-3">
            <button onClick={() => onSkip('prev')} className="p-2 text-stone-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-colors" title="Previous segment">
              <SkipBack size={24} />
            </button>
            <button 
              onClick={onTogglePlay}
              className="w-16 h-16 bg-amber-500 hover:bg-amber-600 text-white rounded-full flex items-center justify-center shadow-lg shadow-amber-200 transition-all hover:scale-105 active:scale-95"
            >
              {playback.isPlaying ? <Pause size={32} /> : <Play size={32} fill="currentColor" className="ml-1" />}
            </button>
            <button onClick={() => onSkip('next')} className="p-2 text-stone-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-colors" title="Next segment">
              <SkipForward size={24} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center gap-2 w-full max-w-xs">
            <div className="flex items-center justify-between w-full px-2">
              <div className="flex items-center gap-2 text-stone-400">
