            />
          </div>

          <div className="flex items-center gap-3 relative" ref={menuRef}>
            <div className="relative">
              <button 
                onClick={() => setIsVoiceMenuOpen(!isVoiceMenuOpen)}
                className={`flex items-center gap-2 px-4 py-3 rounded-2xl border transition-all ${isVoiceMenuOpen ? 'bg-amber-50 border-amber-300 text-amber-700' : 'bg-stone-50 border-stone-200 text-stone-600 hover:bg-stone-100'}`}
              >
                <Settings size={18} className={isVoiceMenuOpen ? 'text-amber-500' : 'text-stone-400'} />
                <span className="text-xs font-bold truncate max-w-[100px] md:max-w-[120px]">{currentVoiceName}</span>
                <ChevronUp size={14} className={`transition-transform duration-200 ${isVoiceMenuOpen ? 'rotate-180' : ''}`} />
