              {isVoiceMenuOpen && (
                <div className="absolute bottom-full right-0 mb-4 w-80 bg-white border border-amber-100 shadow-[0_-10px_40px_rgba(0,0,0,0.15)] rounded-3xl overflow-hidden animate-in fade-in slide-in-from-bottom-4 zoom-in-95">
                  <div className="p-4 bg-amber-50/50 border-b border-amber-100 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <User size={14} className="text-amber-600" />
                      <span className="text-[11px] uppercase tracking-widest font-extrabold text-amber-700">Narrators</span>
                    </div>
                    <span className="text-[10px] font-medium text-amber-600/70 bg-white px-2 py-0.5 rounded-full border border-amber-100">{voices.length} Available</span>
                  </div>
                  <div className="max-h-72 overflow-y-auto py-2 scrollbar-thin scrollbar-thumb-amber-200">
                    {voices.map(v => (
                      <div key={v.voiceURI} className="flex items-center group/item px-2">
                        <button
                          onClick={() => {
                            onVoiceChange(v.voiceURI);
                            setIsVoiceMenuOpen(false);
                          }}
                          className={`flex-1 text-left px-3 py-3 text-xs transition-all flex items-center justify-between rounded-xl
                            ${playback.voiceURI === v.voiceURI 
                              ? 'text-amber-700 bg-amber-50 font-bold' 
                              : 'text-stone-600 hover:bg-stone-50 hover:text-stone-900'}`}
                        >
                          <div className="flex flex-col gap-0.5">
                            <span className="truncate max-w-[160px]">{v.name}</span>
                            <span className="text-[10px] opacity-60 font-medium">{v.lang}</span>
                          </div>
                          {playback.voiceURI === v.voiceURI && <Check size={14} className="text-amber-500" />}
                        </button>
                        <button 
                          onClick={(e) => {
                            e.stopPropagation();
                            onPreviewVoice(v.voiceURI);
                          }}
                          className="p-2 ml-1 text-stone-400 hover:text-amber-500 hover:bg-amber-100 rounded-lg transition-all"
                          title="Preview voice"
                        >
                          <Volume2 size={16} />
                        </button>
                      </div>
                    ))}
                    {voices.length === 0 && (
                      <div className="p-6 text-center">
                        <p className="text-xs text-stone-400 italic mb-2">No matching voices found.</p>
