      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'auto';
    }
    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      document.body.style.overflow = 'auto';
    };
  }, [isVoiceModalOpen]);

  const currentVoice = voices.find(v => v.voiceURI === playback.voiceURI);
  const currentVoiceName = currentVoice?.name || 'Default Voice';

  return (
    <div className="max-w-4xl mx-auto h-full flex flex-col">
      <div className="flex-1 overflow-y-auto px-6 py-12 hide-scrollbar">
        <h1 className="serif text-4xl md:text-5xl font-bold mb-4 text-stone-800 text-center">
          {story.title}
        </h1>
        <div className="flex justify-center items-center gap-4 mb-12">
           <span className="text-xs px-3 py-1 rounded-full font-bold uppercase tracking-widest bg-stone-100 text-stone-600 shadow-sm border border-stone-200">
             Local Synthesis
           </span>
        </div>

        <div className="space-y-4">
          {story.segments.map((segment, idx) => (
            <div 
              key={idx}
              ref={idx === playback.currentSegmentIndex ? activeSegmentRef : null}
              onClick={() => onSegmentClick(idx)}
              className={`
                group relative p-6 rounded-2xl transition-all duration-300 cursor-pointer text-xl leading-relaxed serif border-2
                ${idx === playback.currentSegmentIndex 
                  ? 'bg-white border-amber-300 text-stone-900 shadow-xl scale-[1.02] z-10' 
                  : 'border-transparent text-stone-400 hover:text-stone-600 hover:bg-white/50'}
              `}
            >
              <div className="flex items-start gap-4">
                <span className={`text-xs mt-2 shrink-0 font-mono ${idx === playback.currentSegmentIndex ? 'text-amber-500 font-bold' : 'text-stone-300'}`}>
                  {(idx + 1).toString().padStart(2, '0')}
                </span>
                <span className="flex-1">{segment.text}</span>
              </div>
            </div>
          ))}
        </div>
        <div className="h-60" />
      </div>

      {/* Control Bar */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-50">
        <div className="bg-white/95 backdrop-blur-xl border border-amber-100 shadow-[0_20px_50px_rgba(0,0,0,0.15)] rounded-[2.5rem] p-5 flex flex-col md:flex-row items-center justify-between gap-6 md:gap-4">

          <div className="flex items-center gap-3">
            <button onClick={() => onSkip('prev')} className="p-2 text-stone-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-colors" title="Previous segment">
              <SkipBack size={24} />
            </button>
            <button 
              onClick={onTogglePlay}
              className="w-16 h-16 bg-amber-500 hover:bg-amber-600 text-white rounded-full flex items-center justify-center shadow-lg shadow-amber-200 transition-all hover:scale-105 active:scale-95"
            >
              {playback.isPlaying ? <Pause size={32} /> : <Play size={32} fill="currentColor" className="ml-1" />}
            </button>
            <button onClick={() => onSkip('next')} className="p-2 text-stone-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-colors" title="Next segment">
              <SkipForward size={24} />
            </button>
          </div>

          <div className="flex-1 flex flex-col items-center gap-2 w-full max-w-xs">
            <div className="flex items-center justify-between w-full px-2">
              <div className="flex items-center gap-2 text-stone-400">
                <Gauge size={14} />
                <span className="text-[10px] font-bold uppercase tracking-wider">Speed</span>
              </div>
              <span className="text-sm font-bold text-amber-600">{playback.speed.toFixed(1)}x</span>
            </div>
            <input 
              type="range" 
              min="0.5" 
              max="2.5" 
              step="0.1" 
              value={playback.speed}
              onChange={(e) => onSpeedChange(parseFloat(e.target.value))}
              className="w-full h-2 bg-stone-100 rounded-lg appearance-none cursor-pointer accent-amber-500 hover:accent-amber-600 transition-all"
            />
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setIsVoiceModalOpen(true)}
              className="flex items-center gap-2 px-4 py-3 bg-stone-50 border border-stone-200 text-stone-600 hover:bg-stone-100 rounded-2xl transition-all group"
            >
              <Settings size={18} className="text-stone-400 group-hover:rotate-45 transition-transform duration-300" />
              <span className="text-xs font-bold truncate max-w-[100px] md:max-w-[120px]">{currentVoiceName}</span>
            </button>
          </div>
        </div>
      </div>

      {/* Voice Selection Modal */}
      {isVoiceModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div 
            className="absolute inset-0 bg-stone-900/40 backdrop-blur-sm animate-in fade-in duration-300" 
            onClick={() => setIsVoiceModalOpen(false)} 
          />
          <div 
            ref={modalContentRef}
            className="relative w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-8 duration-300 flex flex-col max-h-[80vh]"
            role="dialog"
            aria-modal="true"
            aria-labelledby="voice-modal-title"
          >
            <div className="px-8 py-6 border-b border-stone-100 flex items-center justify-between bg-amber-50/30">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-amber-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-200">
                  <User size={20} />
                </div>
                <div>
                  <h2 id="voice-modal-title" className="font-bold text-stone-800 tracking-tight">Select Narrator</h2>
                  <p className="text-[10px] uppercase tracking-widest text-amber-600 font-bold">Female Voice Gallery</p>
                </div>
              </div>
              <button 
                onClick={() => setIsVoiceModalOpen(false)}
                className="w-10 h-10 flex items-center justify-center text-stone-400 hover:bg-stone-100 rounded-full transition-colors"
                aria-label="Close"
              >
                <X size={24} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto px-4 py-4 space-y-2 scrollbar-thin scrollbar-thumb-amber-200">
              {voices.length > 0 ? (
                voices.map((v) => (
                  <div 
                    key={v.voiceURI} 
                    className={`flex items-center p-2 rounded-2xl transition-all group border-2 ${
                      playback.voiceURI === v.voiceURI 
                        ? 'bg-amber-50 border-amber-200 ring-2 ring-amber-100 ring-offset-2' 
                        : 'border-transparent hover:bg-stone-50'
                    }`}
                  >
                    <button
                      onClick={() => {
                        onVoiceChange(v.voiceURI);
                        setIsVoiceModalOpen(false);
                      }}
                      className="flex-1 flex items-center gap-4 text-left p-2"
