import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, Zap, FileText } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');

  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  // Strict filtering for female voices only in specific locales
  const getFilteredVoices = (allVoices: SpeechSynthesisVoice[]) => {
    const allowedLocales = ['en-us', 'en-gb', 'en-in', 'es-es'];
    const femaleKeywords = [
      'female', 'woman', 'girl', 'lady', 'samantha', 'victoria', 'karen', 
      'moira', 'tessa', 'kathy', 'zira', 'maria', 'hazel', 'monica', 
      'helena', 'laura', 'susan', 'linda', 'heather', 'alice', 'veena'
    ];
    const maleKeywords = ['male', 'man', 'boy', 'david', 'mark', 'daniel', 'paul', 'george', 'james', 'richard'];

    return allVoices.filter(v => {
      const locale = v.lang.toLowerCase().replace('_', '-');
      const isAllowedLocale = allowedLocales.some(al => locale.startsWith(al));
      if (!isAllowedLocale) return false;

      const nameLower = v.name.toLowerCase();
      const hasMaleKeyword = maleKeywords.some(kw => nameLower.includes(kw));
      if (hasMaleKeyword) return false;

      const hasFemaleKeyword = femaleKeywords.some(kw => nameLower.includes(kw));
      // Google's default voices are often female but don't say so in the name
      const isGoogleFemaleDefault = v.name.includes('Google') && (v.lang.startsWith('en') || v.lang.startsWith('es'));

      return hasFemaleKeyword || isGoogleFemaleDefault;
    });
  };

  const updateVoices = useCallback(() => {
    const allVoices = synthRef.current.getVoices();
    const filtered = getFilteredVoices(allVoices);

    if (filtered.length > 0) {
      setVoices(filtered);
      setPlayback(p => {
        if (!p.voiceURI) {
          const preferred = 
            filtered.find(v => v.name.includes('Google') && v.lang.startsWith('en-US')) ||
            filtered.find(v => v.lang.startsWith('en')) || 
            filtered[0];
          return { ...p, voiceURI: preferred.voiceURI };
        }
        return p;
      });
    }
  }, []);

  useEffect(() => {
    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') {
      synthRef.current.onvoiceschanged = updateVoices;
    }
    const interval = setInterval(() => {
      if (voices.length === 0) updateVoices();
      else clearInterval(interval);
    }, 1500);
    return () => clearInterval(interval);
  }, [updateVoices, voices.length]);

  const stopAudio = useCallback(() => {
    synthRef.current.cancel();
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const handlePreviewVoice = useCallback((voiceURI: string) => {
    synthRef.current.cancel();
    const voice = voices.find(v => v.voiceURI === voiceURI);
    if (!voice) return;

    const utter = new SpeechSynthesisUtterance("I am ready to read your story.");
    utter.voice = voice;
    utter.rate = playback.speed;
    synthRef.current.speak(utter);
  }, [voices, playback.speed]);

  const createStory = (title: string, text: string) => {
    if (!text.trim()) return;
    const segments = segmentText(text);
    const storyId = btoa(title + text.slice(0, 20)).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ 
        id: `${storyId}-${idx}`,
        text: s, 
        status: 'idle' 
      }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const playSegment = useCallback((index: number) => {
    if (!story) return;
    stopAudio();

    const segment = story.segments[index];
    const utter = new SpeechSynthesisUtterance(segment.text);

    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;

    utter.rate = playback.speed;
    utter.onend = () => {
      setPlayback(prev => {
        if (prev.isPlaying && index + 1 < story.segments.length) {
          return { ...prev, currentSegmentIndex: index + 1 };
        }
        return { ...prev, isPlaying: false };
      });
    };
    utter.onerror = (e) => {
      if (e.error !== 'interrupted') {
        setError("Something went wrong with the voice engine.");
        setPlayback(p => ({ ...p, isPlaying: false }));
      }
    };

    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="min-h-screen bg-[#FFF9F2] flex flex-col selection:bg-amber-100 selection:text-amber-900">
      <header className="border-b border-amber-100/30 bg-white/60 backdrop-blur-2xl sticky top-0 z-[60]">
        <div className="max-w-6xl mx-auto px-4 md:px-6 h-14 md:h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 md:gap-3">
            <div className="w-8 h-8 md:w-10 md:h-10 bg-gradient-to-br from-amber-400 to-orange-500 rounded-xl md:rounded-2xl flex items-center justify-center text-white shadow-lg shadow-amber-100">
              <Sparkles size={18} className="md:w-[22px]" />
            </div>
            <div>
              <span className="font-black text-lg md:text-xl tracking-tight text-stone-800 block leading-none">KittenReader</span>
              <span className="text-[9px] md:text-[10px] font-bold text-amber-600 uppercase tracking-widest">Offline Female TTS</span>
            </div>
          </div>

          {story && (
            <button 
              onClick={() => { stopAudio(); setStory(null); }}
              className="w-10 h-10 flex items-center justify-center text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
            >
              <X size={24} />
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 overflow-x-hidden relative">
        {error && (
          <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[70] w-full max-w-md px-4 animate-in fade-in slide-in-from-top-4">
            <div className="bg-red-50 border border-red-100 text-red-700 px-4 py-3 rounded-2xl flex items-start gap-3 shadow-xl">
              <AlertCircle className="shrink-0 mt-0.5" size={18} />
              <div className="flex-1 text-sm font-medium">{error}</div>
              <button onClick={() => setError(null)} className="shrink-0 opacity-50 hover:opacity-100"><X size={16} /></button>
            </div>
          </div>
        )}

        {!story ? (
          <div className="max-w-5xl mx-auto px-4 md:px-6 py-8 md:py-16">
            <div className="text-center mb-8 md:mb-16">
              <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-amber-100/50 text-amber-700 text-[10px] md:text-xs font-bold uppercase tracking-widest mb-4 md:mb-6">
                <Zap size={12} className="md:w-[14px]" /> 100% Client-Side Private
              </div>
              <h2 className="serif text-4xl md:text-7xl font-bold text-stone-800 mb-4 md:mb-6 leading-tight">
                Reading made <br/><span className="text-amber-500 italic">effortless.</span>
              </h2>
              <p className="text-stone-500 text-base md:text-xl max-w-2xl mx-auto font-medium">
                Transform any document into a high-quality narrated experience. No servers, no tracking, just pure sound.
              </p>
            </div>

            <div className="grid lg:grid-cols-2 gap-4 md:gap-8 max-w-4xl mx-auto">
              <label className="group relative bg-white border-2 border-dashed border-amber-200 rounded-[2rem] md:rounded-[2.5rem] p-8 md:p-12 flex flex-col items-center gap-4 md:gap-6 hover:border-amber-400 hover:bg-amber-50/20 transition-all cursor-pointer shadow-sm hover:shadow-xl hover:-translate-y-1 active:scale-[0.98]">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                   const file = e.target.files?.[0];
                   if (file) {
                     setError(null);
                     try {
                       const text = await parseFile(file);
                       createStory(file.name.split('.')[0], text);
                     } catch (err: any) { setError(err.message); }
                   }
                }} />
                <div className="w-16 h-16 md:w-20 md:h-20 rounded-3xl bg-amber-50 group-hover:bg-amber-500 flex items-center justify-center text-amber-500 group-hover:text-white transition-all duration-500">
                  <Upload size={32} className="md:w-[36px]" />
                </div>
                <div className="text-center">
                  <p className="font-bold text-lg md:text-xl text-stone-800 mb-1">Upload Story</p>
                  <p className="text-xs md:text-sm font-medium text-stone-400">PDF, Word, or TXT</p>
                </div>
              </label>

              <div className="flex flex-col gap-3 md:gap-4">
                <textarea 
                  placeholder="Or paste your text here..."
                  className="w-full h-40 md:h-48 p-5 md:p-6 bg-white border border-amber-100 rounded-[2rem] md:rounded-[2.5rem] focus:ring-4 focus:ring-amber-500/10 focus:border-amber-400 outline-none resize-none text-stone-700 text-base md:text-lg serif shadow-sm transition-all"
                  value={pastedText}
                  onChange={(e) => setPastedText(e.target.value)}
                />
                <button 
                  onClick={() => createStory("New Chapter", pastedText)}
                  disabled={!pastedText.trim()}
                  className="w-full py-4 md:py-5 bg-stone-900 text-white rounded-[1.5rem] md:rounded-[2rem] font-bold text-base md:text-lg hover:bg-amber-500 hover:shadow-xl hover:shadow-amber-100 disabled:opacity-30 disabled:pointer-events-none transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                >
                  <FileText size={20} />
                  Start Listening
                </button>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            voices={voices}
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
            onPreviewVoice={handlePreviewVoice}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, Settings, Gauge, User, Check, X, Volume2, ChevronRight } from 'lucide-react';
import { Story, PlaybackState } from '../types';

interface ReaderProps {
  story: Story;
  playback: PlaybackState;
  voices: SpeechSynthesisVoice[];
  onTogglePlay: () => void;
  onSkip: (direction: 'prev' | 'next') => void;
  onVoiceChange: (voiceURI: string) => void;
  onPreviewVoice: (voiceURI: string) => void;
  onSpeedChange: (speed: number) => void;
  onSegmentClick: (index: number) => void;
}

const Reader: React.FC<ReaderProps> = ({ 
  story, 
  playback, 
  voices,
  onTogglePlay, 
  onSkip, 
  onVoiceChange,
  onPreviewVoice,
  onSpeedChange,
  onSegmentClick 
}) => {
  const activeSegmentRef = useRef<HTMLDivElement>(null);
  const [isVoiceModalOpen, setIsVoiceModalOpen] = useState(false);
  const modalContentRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (activeSegmentRef.current) {
      activeSegmentRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [playback.currentSegmentIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setIsVoiceModalOpen(false);
    };
    if (isVoiceModalOpen) {
      document.addEventListener('keydown', handleKeyDown);
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'auto';
    }
    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      document.body.style.overflow = 'auto';
    };
  }, [isVoiceModalOpen]);

  const currentVoice = voices.find(v => v.voiceURI === playback.voiceURI);
  const currentVoiceName = currentVoice?.name || 'System Default';

  return (
    <div className="max-w-4xl mx-auto h-full flex flex-col">
      <div className="flex-1 overflow-y-auto px-4 md:px-6 py-10 md:py-16 hide-scrollbar">
        <h1 className="serif text-3xl md:text-5xl font-bold mb-4 text-stone-800 text-center px-4">
          {story.title}
        </h1>
        <div className="flex justify-center items-center gap-4 mb-10 md:mb-16">
           <span className="text-[10px] md:text-xs px-3 py-1 rounded-full font-bold uppercase tracking-widest bg-amber-50 text-amber-600 shadow-sm border border-amber-100">
             Local Audio
           </span>
        </div>

        <div className="space-y-4 md:space-y-6">
          {story.segments.map((segment, idx) => (
            <div 
              key={idx}
              ref={idx === playback.currentSegmentIndex ? activeSegmentRef : null}
              onClick={() => onSegmentClick(idx)}
              className={`
                group relative p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] transition-all duration-500 cursor-pointer text-lg md:text-2xl leading-relaxed md:leading-snug serif border-2
                ${idx === playback.currentSegmentIndex 
                  ? 'bg-white border-amber-300 text-stone-900 shadow-xl shadow-amber-500/5 scale-[1.01] z-10' 
                  : 'border-transparent text-stone-400 hover:text-stone-600 hover:bg-white/40'}
              `}
            >
              <div className="flex items-start gap-4 md:gap-6">
                <span className={`text-[10px] md:text-xs mt-2 md:mt-3 shrink-0 font-mono ${idx === playback.currentSegmentIndex ? 'text-amber-500 font-bold' : 'text-stone-200'}`}>
                  {(idx + 1).toString().padStart(2, '0')}
                </span>
                <span className="flex-1 transition-colors duration-500">{segment.text}</span>
              </div>
            </div>
          ))}
        </div>
        <div className="h-48 md:h-60" />
      </div>

