            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8 max-w-6xl mx-auto">
              {/* Option 1: File Upload */}
              <label className="group relative bg-white border-2 border-dashed border-amber-200 rounded-[2.5rem] p-10 flex flex-col items-center gap-6 hover:border-amber-400 hover:bg-amber-50/20 transition-all cursor-pointer shadow-sm hover:shadow-xl hover:-translate-y-1 active:scale-[0.98]">
                <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                   const file = e.target.files?.[0];
