                >
                  Listen Now
                </button>
              </div>

              {/* Option 3: URL Fetch */}
              <div className="flex flex-col gap-4 bg-white p-6 rounded-[2.5rem] shadow-sm border border-amber-100/50 hover:shadow-xl transition-all hover:-translate-y-1">
