                   <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-600">
                     <LinkIcon size={20} />
                   </div>
                   <p className="font-bold text-stone-800">From Web</p>
                </div>
                <div className="flex-1 flex flex-col justify-center gap-4">
                  <div className="relative">
                    <input 
                      type="url"
                      placeholder="https://example.com/article"
                      className="w-full p-4 pl-12 bg-stone-50/50 border border-stone-100 rounded-2xl focus:ring-4 focus:ring-amber-500/10 focus:border-amber-400 outline-none text-stone-700 text-sm transition-all"
                      value={urlInput}
                      onChange={(e) => setUrlInput(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && fetchFromUrl()}
                    />
                    <LinkIcon size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" />
                  </div>
                  <p className="text-[10px] text-stone-400 font-medium px-1">
                    Enter an article link. We'll use Gemini to extract the text for you.
                  </p>
                </div>
                <button 
                  onClick={fetchFromUrl}
                  disabled={!urlInput.trim() || isFetchingUrl}
                  className="w-full py-4 bg-amber-500 text-white rounded-2xl font-bold text-base hover:bg-amber-600 disabled:opacity-30 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                >
                  {isFetchingUrl ? <Loader2 size={20} className="animate-spin" /> : <Sparkles size={18} />}
                  {isFetchingUrl ? 'Fetching...' : 'Fetch Content'}
                </button>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            voices={voices}
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
            onPreviewVoice={handlePreviewVoice}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

