              </div>

              {/* Paste Text Card */}
              <div className="md:col-span-12 bg-stone-900 text-white rounded-[3rem] p-8 md:p-12 flex flex-col md:flex-row items-center gap-8 md:gap-12 shadow-2xl overflow-hidden relative group">
                <div className="absolute top-0 right-0 w-64 h-64 bg-teal-500/10 blur-[80px] rounded-full group-hover:scale-150 transition-transform duration-700" />
                <div className="flex-1 space-y-4 relative z-10">
                   <div className="flex items-center gap-3">
                     <div className="w-12 h-12 rounded-2xl bg-white/10 backdrop-blur-md flex items-center justify-center">
                       <Layout size={24} className="text-teal-400" />
                     </div>
                     <h3 className="text-2xl font-bold">Quick Narrate</h3>
                   </div>
                   <p className="text-stone-400 font-medium">Have something short? Just drop your text here and we'll start the experience immediately.</p>
                </div>
                <div className="w-full md:w-[400px] flex flex-col gap-4 relative z-10">
                  <textarea 
                    placeholder="Enter or paste text here..."
                    className="w-full h-32 p-5 bg-white/5 border border-white/10 rounded-3xl focus:border-teal-400/50 outline-none resize-none text-white text-base font-medium placeholder:text-stone-600 transition-all"
                    value={pastedText}
                    onChange={(e) => setPastedText(e.target.value)}
                  />
                  <button 
                    onClick={() => createStory("Unspoken Thoughts", pastedText)}
                    disabled={!pastedText.trim()}
                    className="w-full py-4 bg-white text-stone-900 rounded-2xl font-bold hover:bg-teal-400 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                  >
                    <BookOpen size={20} />
                    Start Reading
                  </button>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <Reader 
            story={story} 
            playback={playback} 
            voices={voices}
            onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
            onSkip={(dir) => {
              const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
              setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
            }}
            onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
            onPreviewVoice={handlePreviewVoice}
            onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
            onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
