            role="dialog"
            aria-modal="true"
          >
            <div className="px-8 py-8 border-b border-stone-50 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-teal-500 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-teal-100">
                  <Music size={24} />
                </div>
                <div>
                  <h2 className="font-bold text-2xl text-stone-900 tracking-tight">Narrators</h2>
                  <p className="text-[10px] font-black text-teal-600 uppercase tracking-widest">Hand-picked female voices</p>
                </div>
              </div>
              <button 
                onClick={() => setIsVoiceModalOpen(false)}
                className="w-12 h-12 flex items-center justify-center text-stone-300 hover:text-stone-900 hover:bg-stone-50 rounded-full transition-all"
