                  style={{ 
                    height: `${Math.random() * 20 + 4}px`, 
                    animationDelay: `${i * 0.05}s`,
                    opacity: i / 40 > (playback.currentSegmentIndex / story.segments.length) ? 0.3 : 1
                  }} 
