             ))}
             <div className="absolute h-10 w-0.5 bg-teal-400" style={{ left: `${(playback.currentSegmentIndex / story.segments.length) * 100}%` }} />
          </div>
          <span className="text-[10px] font-black text-stone-500 w-10 text-right">-16:36</span>
        </div>

        {/* Action Buttons */}
        <div className="flex items-center justify-around gap-4 px-2">
          <button className="w-12 h-12 rounded-full bg-white/60 flex items-center justify-center text-stone-500 shadow-sm active:scale-90 transition-transform">
             <Bookmark size={18} />
          </button>

          <div className="flex items-center gap-6">
             <button onClick={() => onSkip('prev')} className="text-stone-400 p-2 hover:text-stone-900 transition-colors">
               <SkipBack size={24} fill="currentColor" />
             </button>
             <button 
                onClick={onTogglePlay}
                className="w-20 h-20 bg-black text-white rounded-[2rem] flex items-center justify-center shadow-2xl shadow-stone-900/20 active:scale-95 transition-all"
             >
                {playback.isPlaying ? <Pause size={32} fill="white" /> : <Play size={32} fill="white" className="ml-1" />}
             </button>
             <button onClick={() => onSkip('next')} className="text-stone-400 p-2 hover:text-stone-900 transition-colors">
               <SkipForward size={24} fill="currentColor" />
