          <button onClick={() => setIsVoiceModalOpen(true)} className="w-12 h-12 rounded-full bg-white/60 flex items-center justify-center text-stone-50 shadow-sm active:scale-90 transition-transform relative">
             <RotateCcw size={18} className="text-stone-500" />
