                   <div className={`w-10 h-10 rounded-xl flex items-center justify-center mr-4 ${
                     playback.voiceURI === v.voiceURI ? 'bg-purple-500 text-white shadow-lg shadow-purple-200' : 'bg-stone-100 text-stone-400'
                   }`}>
                     {playback.voiceURI === v.voiceURI ? <Check size={20} /> : <User size={18} />}
                   </div>
                   <div className="flex-1">
                     <p className="font-bold text-sm text-stone-800">{v.name}</p>
                     <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">{v.lang}</p>
