               ))}
             </div>

             <div className="flex items-center gap-4 pt-4 border-t border-stone-50">
               <div className="flex-1">
                 <p className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-2">Reading Speed</p>
                 <input 
                    type="range" min="0.5" max="2" step="0.1" value={playback.speed} 
                    onChange={e => onSpeedChange(parseFloat(e.target.value))}
                    className="w-full h-1.5 accent-purple-600 bg-stone-100 rounded-lg appearance-none cursor-pointer"
                  />
               </div>
               <span className="text-sm font-black text-purple-600 w-10 text-right">{playback.speed.toFixed(1)}x</span>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

