import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, FileText, Link as LinkIcon, Loader2, BookOpen, Globe, Layout, ShieldCheck, Headphones, Mic, MessageSquare } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isFetchingUrl, setIsFetchingUrl] = useState(false);
  const [activeInput, setActiveInput] = useState<'upload' | 'url' | 'paste' | null>(null);

  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  const getFilteredVoices = (allVoices: SpeechSynthesisVoice[]) => {
    const allowedLocales = ['en-us', 'en-gb', 'en-in', 'es-es'];
    const femaleKeywords = ['female', 'woman', 'girl', 'lady', 'samantha', 'victoria', 'karen', 'moira', 'tessa', 'kathy', 'zira', 'maria', 'hazel', 'monica', 'helena', 'laura', 'susan', 'linda', 'heather', 'alice', 'veena'];
    const maleKeywords = ['male', 'man', 'boy', 'david', 'mark', 'daniel', 'paul', 'george', 'james', 'richard'];

    return allVoices.filter(v => {
      const locale = v.lang.toLowerCase().replace('_', '-');
      const isAllowedLocale = allowedLocales.some(al => locale.startsWith(al));
      if (!isAllowedLocale) return false;
      const nameLower = v.name.toLowerCase();
      if (maleKeywords.some(kw => nameLower.includes(kw))) return false;
      const hasFemaleKeyword = femaleKeywords.some(kw => nameLower.includes(kw));
      const isGoogleFemaleDefault = v.name.includes('Google') && (v.lang.startsWith('en') || v.lang.startsWith('es'));
      return hasFemaleKeyword || isGoogleFemaleDefault;
    });
  };

  const updateVoices = useCallback(() => {
    const allVoices = synthRef.current.getVoices();
    const filtered = getFilteredVoices(allVoices);
    if (filtered.length > 0) {
      setVoices(filtered);
      setPlayback(p => {
        if (!p.voiceURI) {
          const preferred = filtered.find(v => v.name.includes('Google') && v.lang.startsWith('en-US')) || filtered.find(v => v.lang.startsWith('en')) || filtered[0];
          return { ...p, voiceURI: preferred.voiceURI };
        }
        return p;
      });
    }
  }, []);

  useEffect(() => {
    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') synthRef.current.onvoiceschanged = updateVoices;
    const interval = setInterval(() => { if (voices.length === 0) updateVoices(); else clearInterval(interval); }, 1500);
    return () => clearInterval(interval);
  }, [updateVoices, voices.length]);

  const stopAudio = useCallback(() => {
    synthRef.current.cancel();
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const handlePreviewVoice = useCallback((voiceURI: string) => {
    synthRef.current.cancel();
    const voice = voices.find(v => v.voiceURI === voiceURI);
    if (!voice) return;
    const utter = new SpeechSynthesisUtterance("I am ready to read your story.");
    utter.voice = voice;
    utter.rate = playback.speed;
    synthRef.current.speak(utter);
  }, [voices, playback.speed]);

  const createStory = (title: string, text: string) => {
    if (!text.trim()) return;
    const segments = segmentText(text);
    const storyId = btoa(title + text.slice(0, 20)).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ id: `${storyId}-${idx}`, text: s, status: 'idle' }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const fetchFromUrl = async () => {
    if (!urlInput.trim()) return;
    setIsFetchingUrl(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Extract the main text from: ${urlInput}. Return ONLY text.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      const extractedText = response.text;
      if (!extractedText || extractedText.length < 50) throw new Error("Short content.");
      const titleMatch = urlInput.match(/([^\/]+)(?=\/?$)/);
      createStory(titleMatch ? titleMatch[0].replace(/-/g, ' ') : "Web Story", extractedText);
    } catch (err) {
      setError("Unable to process URL.");
    } finally {
      setIsFetchingUrl(false);
    }
  };

  const playSegment = useCallback((index: number) => {
    if (!story) return;
    stopAudio();
    const segment = story.segments[index];
    const utter = new SpeechSynthesisUtterance(segment.text);
    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;
    utter.rate = playback.speed;
    utter.onend = () => {
      setPlayback(prev => {
        if (prev.isPlaying && index + 1 < story.segments.length) return { ...prev, currentSegmentIndex: index + 1 };
        return { ...prev, isPlaying: false };
      });
    };
    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) playSegment(playback.currentSegmentIndex);
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="h-screen w-full flex flex-col bg-gradient-to-br from-[#E9D5FF] via-[#F3E8FF] to-[#FFFFFF] overflow-hidden">
      {!story ? (
        <div className="flex-1 flex flex-col px-6 pt-8 pb-4 max-w-lg mx-auto w-full relative">
          {/* Header Area */}
          <div className="mb-6 animate-in fade-in slide-in-from-top-4 duration-700">
            <div className="flex items-center justify-between mb-4">
              <button className="p-2 text-stone-400">
                <div className="w-6 h-0.5 bg-white rounded-full mb-1" />
                <div className="w-4 h-0.5 bg-white rounded-full" />
              </button>
              <div className="w-10 h-10 rounded-xl glass flex items-center justify-center shadow-sm overflow-hidden">
                <img src="https://flagcdn.com/w80/us.png" className="w-full h-full object-cover opacity-80" alt="lang" />
              </div>
            </div>

            <p className="text-white/80 font-bold mb-1 text-sm">Hello Reader,</p>
            <h1 className="text-4xl font-black text-white tracking-tight leading-tight">
              Continue <br/>Listening!
            </h1>
          </div>

          <div className="flex items-center justify-between mb-4">
            <h2 className="font-bold text-white/70 text-sm tracking-wide">Your Lessons</h2>
            <div className="flex gap-2">
              <div className="w-8 h-8 rounded-lg glass flex items-center justify-center text-white/50">
                 <Layout size={14} />
              </div>
              <div className="w-8 h-8 rounded-lg glass flex items-center justify-center text-white/70">
                 <div className="flex flex-col gap-0.5">
                   <div className="w-3 h-0.5 bg-white/70 rounded-full" />
                   <div className="w-3 h-0.5 bg-white/70 rounded-full" />
                 </div>
              </div>
            </div>
          </div>

          {/* Grid Area */}
          <div className="grid grid-cols-2 gap-4 flex-1 mb-4 overflow-hidden">
            {/* Reading Card */}
            <label className="bg-white rounded-[2.5rem] p-5 flex flex-col items-start gap-3 shadow-xl shadow-purple-200/20 group hover:scale-[1.02] transition-all cursor-pointer relative overflow-hidden">
              <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                 const file = e.target.files?.[0];
                 if (file) try { createStory(file.name.split('.')[0], await parseFile(file)); } catch (err: any) { setError(err.message); }
              }} />
              <div className="relative w-14 h-14">
                 <svg className="absolute inset-0 w-full h-full -rotate-90">
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#F3E8FF" strokeWidth="2" />
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#8B5CF6" strokeWidth="2" strokeDasharray="163.3" strokeDashoffset="40" strokeLinecap="round" />
                 </svg>
                 <div className="absolute inset-0 flex items-center justify-center">
                    <BookOpen size={20} className="text-purple-600" />
                 </div>
              </div>
              <div>
                <p className="font-bold text-stone-800 text-sm">Reading</p>
                <p className="text-[10px] font-bold text-stone-400">74% completed</p>
              </div>
            </label>

            {/* Listening (URL) Card */}
            <div 
              onClick={() => setActiveInput(activeInput === 'url' ? null : 'url')}
              className="bg-white rounded-[2.5rem] p-5 flex flex-col items-start gap-3 shadow-xl shadow-purple-200/20 hover:scale-[1.02] transition-all cursor-pointer overflow-hidden relative"
            >
              <div className="relative w-14 h-14">
                 <svg className="absolute inset-0 w-full h-full -rotate-90">
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#FCE7F3" strokeWidth="2" />
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#EC4899" strokeWidth="2" strokeDasharray="163.3" strokeDashoffset="70" strokeLinecap="round" />
                 </svg>
                 <div className="absolute inset-0 flex items-center justify-center">
                    <Headphones size={20} className="text-pink-400" />
                 </div>
              </div>
              <div>
                <p className="font-bold text-stone-800 text-sm">Listening</p>
                <p className="text-[10px] font-bold text-stone-400">59% completed</p>
              </div>
              {activeInput === 'url' && (
                <div className="absolute inset-0 bg-white p-3 flex flex-col gap-2 animate-in slide-in-from-bottom-2">
                  <input autoFocus placeholder="URL..." className="w-full text-xs p-2 bg-stone-50 rounded-lg outline-none" value={urlInput} onChange={e => setUrlInput(e.target.value)} onClick={e => e.stopPropagation()} />
                  <button onClick={(e) => { e.stopPropagation(); fetchFromUrl(); }} className="w-full py-2 bg-pink-500 text-white text-[10px] font-bold rounded-lg uppercase">
                    {isFetchingUrl ? '...' : 'Fetch'}
                  </button>
                </div>
              )}
            </div>

            {/* Speaking (Paste) Card */}
            <div 
              onClick={() => setActiveInput(activeInput === 'paste' ? null : 'paste')}
              className="bg-white rounded-[2.5rem] p-5 flex flex-col items-start gap-3 shadow-xl shadow-purple-200/20 hover:scale-[1.02] transition-all cursor-pointer relative overflow-hidden"
            >
              <div className="relative w-14 h-14">
                 <svg className="absolute inset-0 w-full h-full -rotate-90">
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#FFEDD5" strokeWidth="2" />
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#FB923C" strokeWidth="2" strokeDasharray="163.3" strokeDashoffset="100" strokeLinecap="round" />
                 </svg>
                 <div className="absolute inset-0 flex items-center justify-center">
                    <Mic size={20} className="text-orange-400" />
                 </div>
              </div>
              <div>
                <p className="font-bold text-stone-800 text-sm">Speaking</p>
                <p className="text-[10px] font-bold text-stone-400">22% completed</p>
              </div>
              {activeInput === 'paste' && (
                <div className="absolute inset-0 bg-white p-3 flex flex-col gap-2 animate-in slide-in-from-bottom-2">
                  <textarea autoFocus placeholder="Paste..." className="w-full flex-1 text-xs p-2 bg-stone-50 rounded-lg outline-none resize-none" value={pastedText} onChange={e => setPastedText(e.target.value)} onClick={e => e.stopPropagation()} />
                  <button onClick={(e) => { e.stopPropagation(); createStory("New Paste", pastedText); }} className="w-full py-2 bg-orange-400 text-white text-[10px] font-bold rounded-lg uppercase">
                    Go
                  </button>
                </div>
              )}
            </div>

            {/* Conversation Card */}
            <div className="bg-white rounded-[2.5rem] p-5 flex flex-col items-start gap-3 shadow-xl shadow-purple-200/20 group hover:scale-[1.02] transition-all cursor-pointer">
              <div className="relative w-14 h-14">
                 <svg className="absolute inset-0 w-full h-full -rotate-90">
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#E0E7FF" strokeWidth="2" />
                   <circle cx="28" cy="28" r="26" fill="none" stroke="#6366F1" strokeWidth="2" strokeDasharray="163.3" strokeDashoffset="120" strokeLinecap="round" />
                 </svg>
                 <div className="absolute inset-0 flex items-center justify-center">
                    <MessageSquare size={20} className="text-indigo-400" />
                 </div>
              </div>
              <div>
                <p className="font-bold text-stone-800 text-sm">Conversation</p>
                <p className="text-[10px] font-bold text-stone-400">8% completed</p>
              </div>
            </div>
          </div>

          {/* Bottom Nav Bar */}
          <div className="flex items-center justify-around text-white/50 pb-2">
             <button className="p-2"><Sparkles size={22} /></button>
             <button className="p-2"><Mic size={22} /></button>
             <button className="p-2 relative">
               <div className="w-1.5 h-1.5 bg-pink-500 rounded-full absolute top-2 right-2 border border-purple-200" />
               <Headphones size={22} className="text-white" />
             </button>
             <button className="p-2"><X size={22} /></button>
          </div>
        </div>
      ) : (
        <Reader 
          story={story} 
          playback={playback} 
          voices={voices}
          onBack={() => { stopAudio(); setStory(null); }}
          onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
          onSkip={(dir) => {
            const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
            setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
          }}
          onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
          onPreviewVoice={handlePreviewVoice}
          onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
          onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
        />
      )}

      {error && (
        <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-xs animate-in slide-in-from-bottom-4">
           <div className="bg-white/95 backdrop-blur-md border border-red-100 p-4 rounded-3xl flex items-center gap-3 shadow-2xl">
              <AlertCircle size={18} className="text-red-500" />
              <p className="text-xs font-bold text-red-600">{error}</p>
              <button onClick={() => setError(null)} className="ml-auto text-stone-300"><X size={14} /></button>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
