const CACHE_NAME = 'kitten-reader-v1';
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(['./', './index.html']);
    })
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, FileText, Loader2, Globe, Headphones, Mic } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [volume, setVolume] = useState(1.0);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<string | null>(null);
  const [pastedText, setPastedText] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isFetchingUrl, setIsFetchingUrl] = useState(false);
  const [activeInput, setActiveInput] = useState<'url' | 'paste' | null>(null);

  const synthRef = useRef<SpeechSynthesis>(window.speechSynthesis);

  const getFilteredVoices = (allVoices: SpeechSynthesisVoice[]) => {
    const allowedLocales = ['en-us', 'en-gb', 'en-in', 'es-es'];
    const femaleKeywords = ['female', 'woman', 'girl', 'lady', 'samantha', 'victoria', 'karen', 'moira', 'tessa', 'kathy', 'zira', 'maria', 'hazel', 'monica', 'helena', 'laura', 'susan', 'linda', 'heather', 'alice', 'veena'];
    const maleKeywords = ['male', 'man', 'boy', 'david', 'mark', 'daniel', 'paul', 'george', 'james', 'richard'];

    return allVoices.filter(v => {
      const locale = v.lang.toLowerCase().replace('_', '-');
      const isAllowedLocale = allowedLocales.some(al => locale.startsWith(al));
      if (!isAllowedLocale) return false;
      const nameLower = v.name.toLowerCase();
      if (maleKeywords.some(kw => nameLower.includes(kw))) return false;
      const hasFemaleKeyword = femaleKeywords.some(kw => nameLower.includes(kw));
      const isGoogleFemaleDefault = v.name.includes('Google') && (v.lang.startsWith('en') || v.lang.startsWith('es'));
      return hasFemaleKeyword || isGoogleFemaleDefault;
    });
  };

  const updateVoices = useCallback(() => {
    const allVoices = synthRef.current.getVoices();
    const filtered = getFilteredVoices(allVoices);
    if (filtered.length > 0) {
      setVoices(filtered);
      setPlayback(p => {
        if (!p.voiceURI) {
          const preferred = filtered.find(v => v.name.includes('Google') && v.lang.startsWith('en-US')) || filtered.find(v => v.lang.startsWith('en')) || filtered[0];
          return { ...p, voiceURI: preferred.voiceURI };
        }
        return p;
      });
    }
  }, []);

  useEffect(() => {
    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') synthRef.current.onvoiceschanged = updateVoices;
    const interval = setInterval(() => { if (voices.length === 0) updateVoices(); else clearInterval(interval); }, 1500);
    return () => clearInterval(interval);
  }, [updateVoices, voices.length]);

  const stopAudio = useCallback(() => {
    synthRef.current.cancel();
    setPlayback(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const handlePreviewVoice = useCallback((voiceURI: string) => {
    synthRef.current.cancel();
    const voice = voices.find(v => v.voiceURI === voiceURI);
    if (!voice) return;
    const utter = new SpeechSynthesisUtterance("I am ready to read your story.");
    utter.voice = voice;
    utter.rate = playback.speed;
    utter.volume = volume;
    synthRef.current.speak(utter);
  }, [voices, playback.speed, volume]);

  const createStory = (title: string, text: string) => {
    if (!text.trim()) return;
    const segments = segmentText(text);
    const storyId = btoa(title + text.slice(0, 20)).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ id: `${storyId}-${idx}`, text: s, status: 'idle' }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
  };

  const fetchFromUrl = async () => {
    if (!urlInput.trim()) return;
    setIsFetchingUrl(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Extract the main story text content from: ${urlInput}. Return ONLY the core text, no metadata.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      const extractedText = response.text;
      if (!extractedText || extractedText.length < 50) throw new Error("Short content.");
      const titleMatch = urlInput.match(/([^\/]+)(?=\/?$)/);
      createStory(titleMatch ? titleMatch[0].replace(/-/g, ' ') : "Web Story", extractedText);
    } catch (err) {
      setError("Unable to process URL.");
    } finally {
      setIsFetchingUrl(false);
    }
  };

  const playSegment = useCallback((index: number) => {
    if (!story) return;
    stopAudio();
    const segment = story.segments[index];
    const utter = new SpeechSynthesisUtterance(segment.text);
    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;
    utter.rate = playback.speed;
    utter.volume = volume;
    utter.onend = () => {
      setPlayback(prev => {
        if (prev.isPlaying && index + 1 < story.segments.length) return { ...prev, currentSegmentIndex: index + 1 };
        return { ...prev, isPlaying: false };
      });
    };
    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, volume, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) playSegment(playback.currentSegmentIndex);
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="h-screen w-full flex flex-col bg-[#FDFCFB] overflow-hidden safe-pb">
      {!story ? (
        <div className="flex-1 flex flex-col px-8 pt-16 pb-8 max-w-lg mx-auto w-full relative">
          <div className="mb-12 animate-in fade-in slide-in-from-top-4 duration-1000">
            <h2 className="serif text-5xl font-bold text-stone-900 leading-[1.1] tracking-tight">
              Quiet moments, <br/><span className="italic font-normal text-stone-400">narrated.</span>
            </h2>
          </div>

          <div className="flex flex-col gap-6 flex-1 overflow-hidden">
            <label className="bg-white rounded-[2rem] p-6 flex items-center gap-6 shadow-xl shadow-stone-200/40 border border-stone-50 group hover:scale-[1.01] transition-all cursor-pointer">
              <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                 const file = e.target.files?.[0];
                 if (file) try { createStory(file.name.split('.')[0], await parseFile(file)); } catch (err: any) { setError(err.message); }
              }} />
              <div className="w-16 h-16 rounded-2xl bg-purple-50 flex items-center justify-center text-purple-600 group-hover:bg-purple-600 group-hover:text-white transition-all">
                 <Upload size={28} />
              </div>
              <div className="flex-1">
                <p className="font-bold text-stone-900 text-lg">Local Documents</p>
                <p className="text-xs font-medium text-stone-400">PDF, Word, or TXT</p>
              </div>
            </label>

            <div 
              onClick={() => setActiveInput(activeInput === 'url' ? null : 'url')}
              className="bg-white rounded-[2rem] p-6 flex flex-col gap-4 shadow-xl shadow-stone-200/40 border border-stone-50 hover:scale-[1.01] transition-all cursor-pointer relative overflow-hidden"
            >
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 rounded-2xl bg-pink-50 flex items-center justify-center text-pink-500">
                   <Globe size={28} />
                </div>
                <div className="flex-1">
                  <p className="font-bold text-stone-900 text-lg">Web Content</p>
                  <p className="text-xs font-medium text-stone-400">Paste an article link</p>
                </div>
              </div>
              {activeInput === 'url' && (
                <div className="flex flex-col gap-2 animate-in slide-in-from-top-2">
                  <input autoFocus placeholder="https://..." className="w-full text-sm p-3 bg-stone-50 border border-stone-100 rounded-xl outline-none" value={urlInput} onChange={e => setUrlInput(e.target.value)} onClick={e => e.stopPropagation()} />
                  <button onClick={(e) => { e.stopPropagation(); fetchFromUrl(); }} className="w-full py-3 bg-pink-500 text-white text-xs font-bold rounded-xl uppercase tracking-widest">
                    {isFetchingUrl ? <Loader2 size={16} className="animate-spin mx-auto" /> : 'Fetch Story'}
                  </button>
                </div>
              )}
            </div>

            <div 
              onClick={() => setActiveInput(activeInput === 'paste' ? null : 'paste')}
              className="bg-white rounded-[2rem] p-6 flex flex-col gap-4 shadow-xl shadow-stone-200/40 border border-stone-50 hover:scale-[1.01] transition-all cursor-pointer relative overflow-hidden"
            >
              <div className="flex items-center gap-6">
                <div className="w-16 h-16 rounded-2xl bg-orange-50 flex items-center justify-center text-orange-500">
                   <FileText size={28} />
                </div>
                <div className="flex-1">
                  <p className="font-bold text-stone-900 text-lg">Quick Narrate</p>
                  <p className="text-xs font-medium text-stone-400">Paste your text directly</p>
                </div>
              </div>
              {activeInput === 'paste' && (
                <div className="flex flex-col gap-2 animate-in slide-in-from-top-2">
                  <textarea autoFocus placeholder="Your text here..." className="w-full h-32 text-sm p-3 bg-stone-50 border border-stone-100 rounded-xl outline-none resize-none" value={pastedText} onChange={e => setPastedText(e.target.value)} onClick={e => e.stopPropagation()} />
                  <button onClick={(e) => { e.stopPropagation(); createStory("Quick Note", pastedText); }} className="w-full py-3 bg-stone-900 text-white text-xs font-bold rounded-xl uppercase tracking-widest">
                    Start Reading
                  </button>
                </div>
              )}
            </div>
          </div>

          <div className="mt-auto flex items-center justify-around text-stone-300 pt-6">
             <button className="p-3"><Sparkles size={20} /></button>
             <button className="p-3"><Mic size={20} /></button>
             <button className="p-3 relative">
               <div className="w-1.5 h-1.5 bg-pink-500 rounded-full absolute top-3 right-3 border border-[#FDFCFB]" />
               <Headphones size={20} className="text-stone-900" />
             </button>
             <button className="p-3"><X size={20} /></button>
          </div>
        </div>
      ) : (
        <Reader 
          story={story} 
          playback={playback} 
          voices={voices}
          volume={volume}
          onVolumeChange={setVolume}
          onBack={() => { stopAudio(); setStory(null); }}
          onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
          onSkip={(dir) => {
            const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
            setPlayback(p => ({ ...p, currentSegmentIndex: newIdx }));
          }}
          onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
          onPreviewVoice={handlePreviewVoice}
          onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
          onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
        />
      )}

      {error && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] w-full max-w-xs px-4">
           <div className="bg-white border border-red-50 p-4 rounded-3xl flex items-center gap-3 shadow-2xl">
              <AlertCircle size={18} className="text-red-500" />
              <p className="text-xs font-bold text-red-600">{error}</p>
              <button onClick={() => setError(null)} className="ml-auto text-stone-300"><X size={14} /></button>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

