      </div>

      {isVolumeOpen && (
        <div className="absolute top-16 right-6 z-[120] bg-white p-4 rounded-3xl shadow-2xl border border-stone-100 flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
           <VolumeX size={14} className="text-stone-300" />
           <input 
             type="range" min="0" max="1" step="0.1" value={volume} 
             onChange={e => onVolumeChange(parseFloat(e.target.value))}
             className="w-24 h-1.5 accent-stone-900 bg-stone-100 rounded-full appearance-none cursor-pointer"
           />
           <Volume2 size={14} className="text-stone-900" />
        </div>
