                    <div className="flex flex-col gap-2 p-2">
                       <div className="flex justify-between items-center mb-1">
                          <span className="text-[10px] font-bold text-indigo-600 uppercase">Processing...</span>
                          <span className="text-[10px] font-bold text-indigo-600">{Math.round(batchProgress)}%</span>
                       </div>
                       <div className="w-full h-1.5 bg-indigo-50 rounded-full overflow-hidden">
                          <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${batchProgress}%` }} />
                       </div>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* CARD 3: Web Content */}
            <div 
