           <div className="flex items-center gap-4">
              <span className="text-[10px] font-black text-stone-400 tabular-nums bg-stone-50 px-2 py-1 rounded-md">
                {playback.currentSegmentIndex + 1} / {story.segments.length}
              </span>
              <button 
                onClick={() => setIsVoiceModalOpen(true)}
                className="w-9 h-9 rounded-full bg-stone-100 flex items-center justify-center text-stone-500 hover:text-stone-900 active:scale-90 transition-all shadow-sm"
              >
                <Settings2 size={18} />
              </button>
