            aria-label="Back to Library"
          >
            <ChevronLeft size={28} />
          </button>

          {/* Large Primary Playback Button */}
          <button 
              onClick={onTogglePlay}
              className="flex-1 h-20 bg-stone-900 text-white rounded-[2.5rem] flex items-center justify-center gap-3 shadow-2xl shadow-stone-900/30 active:scale-95 transition-all"
           >
              {playback.isPlaying ? (
                <Pause size={28} fill="white" strokeWidth={1} />
              ) : (
                <Play size={28} fill="white" className="ml-1" strokeWidth={1} />
              )}
              <span className="font-bold text-lg tracking-tight">
                {playback.isPlaying ? 'Pause' : 'Listen'}
              </span>
           </button>

          {/* Bookmark Button - Inside Content Bottom Right */}
          <button 
            className="w-16 h-16 rounded-full bg-stone-100 flex items-center justify-center text-stone-500 active:scale-90 transition-all border border-stone-200/50 shadow-sm"
            aria-label="Bookmark this page"
          >
             <Bookmark size={24} />
          </button>
        </div>

        {/* Subtle Waveform Visualizer */}
