                  style={{ 
                    height: `${Math.random() * 8 + 2}px`, 
                    animationDelay: `${i * 0.03}s`,
                    backgroundColor: (i / 40) <= (playback.currentSegmentIndex / story.segments.length) ? '#000' : '#a8a29e'
                  }} 
                />
             ))}
        </div>
      </div>

      {/* Narrator Settings Modal */}
      {isVoiceModalOpen && (
        <div className="fixed inset-0 z-[130] flex items-end justify-center">
          <div className="absolute inset-0 bg-stone-900/40 backdrop-blur-md" onClick={() => setIsVoiceModalOpen(false)} />
          <div className="relative w-full max-w-lg bg-[#FDFCFB] rounded-t-[4rem] p-10 shadow-2xl animate-in slide-in-from-bottom-full duration-500 border-t border-white">
             <div className="flex items-center justify-between mb-8">
                <div>
                  <h3 className="text-2xl font-black text-stone-900 tracking-tight">Narrator</h3>
                  <p className="text-[10px] text-stone-400 font-bold uppercase tracking-[0.2em] mt-1">Select your favorite voice</p>
                </div>
                <button 
                  onClick={() => setIsVoiceModalOpen(false)} 
                  className="w-12 h-12 rounded-full bg-stone-100 flex items-center justify-center text-stone-500 shadow-inner"
                >
                  <X size={24} />
                </button>
             </div>

             <div className="max-h-[45vh] overflow-y-auto hide-scrollbar space-y-3 pb-8 px-1">
               {voices.map(v => (
                 <div 
                   key={v.voiceURI}
                   onClick={() => { onVoiceChange(v.voiceURI); setIsVoiceModalOpen(false); }}
                   className={`flex items-center p-6 rounded-[2.5rem] cursor-pointer transition-all border ${
                     playback.voiceURI === v.voiceURI 
                       ? 'bg-stone-900 text-white border-stone-900 shadow-xl scale-[1.02]' 
                       : 'bg-white border-stone-100 hover:border-stone-200'
                   }`}
                 >
                   <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mr-5 ${
                     playback.voiceURI === v.voiceURI ? 'bg-white/10 text-white' : 'bg-stone-50 text-stone-400'
                   }`}>
                     {playback.voiceURI === v.voiceURI ? <Check size={20} /> : <User size={20} />}
                   </div>
                   <div className="flex-1">
                     <p className={`font-bold text-base ${playback.voiceURI === v.voiceURI ? 'text-white' : 'text-stone-900'}`}>
                        {v.name}
                     </p>
                     <p className={`text-[10px] font-medium uppercase tracking-wider opacity-60 ${playback.voiceURI === v.voiceURI ? 'text-white' : 'text-stone-400'}`}>
                        {v.lang}
                     </p>
                   </div>
                 </div>
               ))}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

