             <div className="max-h-[40vh] overflow-y-auto hide-scrollbar p-3 space-y-1">
               {voices.map(v => (
                 <div 
                   key={v.voiceURI}
                   onClick={() => { onVoiceChange(v.voiceURI); setIsVoiceModalOpen(false); }}
                   className={`flex items-center gap-3 p-3 rounded-2xl cursor-pointer transition-all ${
                     playback.voiceURI === v.voiceURI 
                       ? 'bg-blue-600 text-white' 
                       : 'hover:bg-stone-50 text-stone-600'
                   }`}
                 >
                   <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 ${playback.voiceURI === v.voiceURI ? 'bg-white/20' : 'bg-stone-50'}`}>
                      <User size={14} />
                   </div>
                   <div className="flex-1 min-w-0">
                     <p className="font-bold text-[13px] truncate">{v.name}</p>
                   </div>
                   {playback.voiceURI === v.voiceURI && <Check size={14} className="text-white shrink-0" />}
