import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import { Mic, MicOff, X, MessageSquareText, Loader2, Volume2 } from 'lucide-react';

// Manual Base64 Helpers as per guidelines
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface LiveConversationProps {
  onClose: () => void;
}

const LiveConversation: React.FC<LiveConversationProps> = ({ onClose }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [transcript, setTranscript] = useState<{ role: 'user' | 'model'; text: string }[]>([]);
  const [currentTranscription, setCurrentTranscription] = useState('');

  const sessionRef = useRef<any>(null);
  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();

    setIsActive(false);
    setIsConnecting(false);
  };

  const startSession = async () => {
    setIsConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            setIsActive(true);

            const source = audioContextInRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (message) => {
            if (message.serverContent?.outputTranscription) {
              setCurrentTranscription(prev => prev + message.serverContent!.outputTranscription!.text);
            }

            if (message.serverContent?.turnComplete) {
              if (currentTranscription) {
                setTranscript(prev => [...prev, { role: 'model', text: currentTranscription }]);
                setCurrentTranscription('');
              }
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && audioContextOutRef.current) {
              const ctx = audioContextOutRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);

              source.addEventListener('ended', () => sourcesRef.current.delete(source));
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => {
                try { s.stop(); } catch(e) {}
              });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Live API Error:', e);
            stopSession();
          },
          onclose: () => {
            setIsActive(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } },
          },
          systemInstruction: 'You are a friendly storyteller companion named Kitten. Speak warmly and creatively.',
          outputAudioTranscription: {},
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setIsConnecting(false);
    }
  };

  useEffect(() => {
    return () => stopSession();
  }, []);

  return (
    <div className="flex-1 flex flex-col h-full bg-[#FDFCFB] animate-in fade-in duration-500">
      <div className="px-6 pt-12 pb-6 flex items-center justify-between">
        <button onClick={onClose} className="p-3 bg-stone-100 rounded-full text-stone-500 hover:bg-stone-200 transition-all">
          <X size={20} />
        </button>
        <div className="flex flex-col items-center">
          <h2 className="serif text-2xl font-bold text-stone-900">Live Chat</h2>
          <p className="text-[9px] font-black uppercase tracking-[0.2em] text-blue-500 mt-1">Real-time Session</p>
        </div>
        <div className="w-11" />
      </div>

      <div className="flex-1 overflow-y-auto px-6 py-4 flex flex-col gap-6 hide-scrollbar">
        {transcript.length === 0 && !isActive && !isConnecting && (
          <div className="flex-1 flex flex-col items-center justify-center text-center px-10">
            <div className="w-20 h-20 bg-blue-50 text-blue-500 rounded-[2.5rem] flex items-center justify-center mb-6 shadow-sm">
              <MessageSquareText size={36} />
            </div>
            <h3 className="text-xl font-bold text-stone-900 mb-2">Voice Companion</h3>
            <p className="text-sm text-stone-400 leading-relaxed">
              Start a real-time conversation with Kitten. Say hello and ask for a story!
            </p>
          </div>
        )}

        <div className="space-y-4">
          {transcript.map((t, i) => (
            <div key={i} className={`flex ${t.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] px-5 py-3.5 rounded-[1.75rem] text-sm font-medium shadow-sm border ${
                t.role === 'user' 
                  ? 'bg-blue-50 border-blue-100 text-blue-900 rounded-tr-none' 
                  : 'bg-white border-stone-100 text-stone-700 rounded-tl-none'
              }`}>
                {t.text}
              </div>
            </div>
          ))}
          {currentTranscription && (
            <div className="flex justify-start">
              <div className="max-w-[85%] px-5 py-3.5 rounded-[1.75rem] rounded-tl-none text-sm font-medium bg-white border border-stone-100 text-stone-400 shadow-sm animate-pulse italic">
                {currentTranscription}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="p-8 flex flex-col items-center gap-6">
        {isActive && (
          <div className="flex items-center gap-2 h-10">
            {[1, 2, 3, 4, 5, 6, 7, 8].map(i => (
              <div 
                key={i} 
                className="w-1.5 bg-blue-400 rounded-full animate-wave" 
                style={{ animationDelay: `${i * 0.1}s`, height: '12px' }} 
              />
            ))}
          </div>
        )}

        <div className="relative">
           {isActive && (
             <div className="absolute inset-0 bg-red-400/20 rounded-full animate-ping" />
           )}
           <button 
            onClick={isActive ? stopSession : startSession}
            disabled={isConnecting}
            className={`relative w-24 h-24 rounded-full flex items-center justify-center shadow-xl transition-all duration-300 active:scale-90 ${
              isActive 
                ? 'bg-red-500 text-white shadow-red-200' 
                : 'bg-blue-600 text-white shadow-blue-200'
            } ${isConnecting ? 'opacity-40 cursor-not-allowed' : ''}`}
          >
            {isConnecting ? (
              <Loader2 size={36} className="animate-spin" />
            ) : isActive ? (
              <MicOff size={36} />
            ) : (
              <Mic size={36} />
            )}
          </button>
        </div>

        <p className="text-[10px] font-black text-stone-400 uppercase tracking-widest">
          {isConnecting ? 'Establishing Link...' : isActive ? 'Listening Now' : 'Tap to converse'}
        </p>
      </div>
    </div>
  );
};

export default LiveConversation;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, FileText, Loader2, Globe, Headphones, Mic, ShieldAlert, MessageSquare } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';
import LiveConversation from './components/LiveConversation';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'library' | 'chat'>('library');
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [volume, setVolume] = useState(1.0);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<{ message: string; type?: 'tts' | 'file' | 'web' } | null>(null);
  const [pastedText, setPastedText] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isFetchingUrl, setIsFetchingUrl] = useState(false);
  const [activeInput, setActiveInput] = useState<'url' | 'paste' | null>(null);

  const synthRef = useRef<SpeechSynthesis | null>(typeof window !== 'undefined' ? window.speechSynthesis : null);

  const getFilteredVoices = (allVoices: SpeechSynthesisVoice[]) => {
    const allowedLocales = ['en-us', 'en-gb', 'en-in', 'es-es'];
    const femaleKeywords = ['female', 'woman', 'girl', 'lady', 'samantha', 'victoria', 'karen', 'moira', 'tessa', 'kathy', 'zira', 'maria', 'hazel', 'monica', 'helena', 'laura', 'susan', 'linda', 'heather', 'alice', 'veena'];

    return allVoices.filter(v => {
      const locale = v.lang.toLowerCase().replace('_', '-');
      const isAllowedLocale = allowedLocales.some(al => locale.startsWith(al));
      if (!isAllowedLocale) return false;
      const nameLower = v.name.toLowerCase();
      const hasFemaleKeyword = femaleKeywords.some(kw => nameLower.includes(kw));
      const isGoogleFemaleDefault = v.name.includes('Google') && (v.lang.startsWith('en') || v.lang.startsWith('es'));
      return hasFemaleKeyword || isGoogleFemaleDefault;
    });
  };

  const updateVoices = useCallback(() => {
    if (!synthRef.current) return;
    const allVoices = synthRef.current.getVoices();
    const filtered = getFilteredVoices(allVoices);
    if (filtered.length > 0) {
      setVoices(filtered);
      setPlayback(p => {
        if (!p.voiceURI) {
          const preferred = filtered.find(v => v.name.includes('Google') && v.lang.startsWith('en-US')) || filtered.find(v => v.lang.startsWith('en')) || filtered[0];
          return { ...p, voiceURI: preferred.voiceURI };
        }
        return p;
      });
    }
  }, []);

  useEffect(() => {
    if (!synthRef.current) {
      setError({ message: "Your browser does not support Speech Synthesis.", type: 'tts' });
      return;
    }

    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') {
      synthRef.current.onvoiceschanged = updateVoices;
    }

    let attempts = 0;
    const interval = setInterval(() => {
      attempts++;
      if (voices.length === 0) updateVoices();
      else clearInterval(interval);
      if (attempts > 10 && voices.length === 0) clearInterval(interval);
    }, 1000);

    return () => clearInterval(interval);
  }, [updateVoices, voices.length]);

  const stopAudio = useCallback(() => {
    if (synthRef.current) {
      synthRef.current.cancel();
      setPlayback(prev => ({ ...prev, isPlaying: false }));
    }
  }, []);

  const handlePreviewVoice = useCallback((voiceURI: string) => {
    if (!synthRef.current) return;
    synthRef.current.cancel();
    const voice = voices.find(v => v.voiceURI === voiceURI);
    if (!voice) return;
    const utter = new SpeechSynthesisUtterance("Hello.");
    utter.voice = voice;
    utter.rate = playback.speed;
    utter.volume = volume;
    synthRef.current.speak(utter);
  }, [voices, playback.speed, volume]);

  const createStory = (title: string, text: string) => {
    if (!text.trim()) return;
    const segments = segmentText(text);
    if (segments.length === 0) return;
    const storyId = btoa(encodeURIComponent(title + text.slice(0, 20))).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ id: `${storyId}-${idx}`, text: s, status: 'idle' }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
    setError(null);
  };

  const fetchFromUrl = async () => {
    if (!urlInput.trim()) return;
    setIsFetchingUrl(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Extract the main story text content from: ${urlInput}. Return ONLY the core text.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      const extractedText = response.text;
      if (!extractedText) throw new Error("Could not extract story.");
      const titleMatch = urlInput.match(/([^\/]+)(?=\/?$)/);
      createStory(titleMatch ? titleMatch[0].replace(/-/g, ' ') : "Web Story", extractedText);
    } catch (err: any) {
      setError({ message: err.message || "Unable to process URL.", type: 'web' });
    } finally {
      setIsFetchingUrl(false);
    }
  };

  const playSegment = useCallback((index: number) => {
    if (!story || !synthRef.current) return;
    stopAudio();
    const segment = story.segments[index];
    if (!segment) return;
    const utter = new SpeechSynthesisUtterance(segment.text);
    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;
    utter.rate = playback.speed;
    utter.volume = volume;
    utter.onend = () => {
      setPlayback(prev => {
        if (prev.isPlaying && index + 1 < story.segments.length) {
          return { ...prev, currentSegmentIndex: index + 1 };
        }
        return { ...prev, isPlaying: false };
      });
    };
    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, volume, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) {
      playSegment(playback.currentSegmentIndex);
    }
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="h-screen w-full flex flex-col bg-[#FDFCFB] overflow-hidden safe-pb">
      {story ? (
        <Reader 
          story={story} 
          playback={playback} 
          voices={voices}
          volume={volume}
          onVolumeChange={setVolume}
          onBack={() => { stopAudio(); setStory(null); }}
          onTogglePlay={() => {
            if (playback.isPlaying) stopAudio();
            else playSegment(playback.currentSegmentIndex);
          }}
          onSkip={(dir) => {
            const newIdx = dir === 'next' ? Math.min(playback.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(playback.currentSegmentIndex - 1, 0);
            setPlayback(p => ({ ...p, currentSegmentIndex: newIdx, isPlaying: true }));
          }}
          onVoiceChange={(vURI) => { 
            stopAudio(); 
            setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); 
          }}
          onPreviewVoice={handlePreviewVoice}
          onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
          onSegmentClick={(idx) => {
            setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }));
          }}
        />
      ) : activeTab === 'chat' ? (
        <LiveConversation onClose={() => setActiveTab('library')} />
      ) : (
        <div className="flex-1 flex flex-col px-8 pt-12 pb-8 max-w-lg mx-auto w-full relative">
          <div className="mb-8 flex items-center justify-between">
            <h2 className="serif text-4xl font-bold text-stone-900 tracking-tight">Kitten.</h2>
            <div className="flex bg-stone-100 p-1 rounded-2xl">
              <button 
                onClick={() => setActiveTab('library')}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'library' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400'}`}
              >
                Library
              </button>
              <button 
                onClick={() => setActiveTab('chat')}
                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'chat' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400'}`}
              >
                Converse
              </button>
            </div>
          </div>

          <div className="flex flex-col gap-4 flex-1 overflow-y-auto hide-scrollbar pb-10">
            {/* Library Options */}
            <label className="bg-white rounded-[2.5rem] p-5 flex items-center gap-6 shadow-xl shadow-stone-200/40 border border-stone-50 group hover:scale-[1.01] transition-all cursor-pointer">
              <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                 const file = e.target.files?.[0];
                 if (file) {
                   try { 
                     const text = await parseFile(file);
                     createStory(file.name.split('.')[0], text); 
                   } catch (err: any) { 
                     setError({ message: "Failed to read file.", type: 'file' }); 
                   }
                 }
              }} />
              <div className="w-14 h-14 rounded-2xl bg-blue-50 flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all">
                 <Upload size={24} />
              </div>
              <div className="flex-1">
                <p className="font-bold text-stone-900 text-lg leading-tight">Read Document</p>
                <p className="text-[10px] font-bold text-stone-300 uppercase tracking-widest mt-0.5">PDF, Word, or TXT</p>
              </div>
            </label>

            <div 
              onClick={() => setActiveInput(activeInput === 'url' ? null : 'url')}
              className="bg-white rounded-[2.5rem] p-5 flex flex-col gap-4 shadow-xl shadow-stone-200/40 border border-stone-50 hover:scale-[1.01] transition-all cursor-pointer relative"
            >
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 rounded-2xl bg-pink-50 flex items-center justify-center text-pink-500">
                   <Globe size={24} />
                </div>
                <div className="flex-1">
                  <p className="font-bold text-stone-900 text-lg leading-tight">Web Article</p>
                  <p className="text-[10px] font-bold text-stone-300 uppercase tracking-widest mt-0.5">Narrate from Link</p>
                </div>
              </div>
              {activeInput === 'url' && (
                <div className="flex flex-col gap-2 animate-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
                  <input autoFocus placeholder="https://..." className="w-full text-sm p-3 bg-stone-50 border border-stone-100 rounded-xl outline-none" value={urlInput} onChange={e => setUrlInput(e.target.value)} />
                  <button onClick={fetchFromUrl} className="w-full py-3 bg-pink-500 text-white text-xs font-bold rounded-xl uppercase tracking-widest">
                    {isFetchingUrl ? <Loader2 size={16} className="animate-spin mx-auto" /> : 'Fetch Story'}
                  </button>
                </div>
              )}
            </div>

            <div 
              onClick={() => setActiveInput(activeInput === 'paste' ? null : 'paste')}
              className="bg-white rounded-[2.5rem] p-5 flex flex-col gap-4 shadow-xl shadow-stone-200/40 border border-stone-50 hover:scale-[1.01] transition-all cursor-pointer relative"
            >
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 rounded-2xl bg-orange-50 flex items-center justify-center text-orange-500">
