import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import { Mic, MicOff, X, MessageSquareText, Loader2, Sparkles, UserCircle } from 'lucide-react';

// Manual Base64 Helpers
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface LiveConversationProps {
  onClose: () => void;
  initialContext?: string;
}

const LiveConversation: React.FC<LiveConversationProps> = ({ onClose, initialContext }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [transcript, setTranscript] = useState<{ role: 'user' | 'model'; text: string }[]>([]);
  const [currentTranscription, setCurrentTranscription] = useState('');
  const [mode, setMode] = useState<'normal' | 'character'>('normal');

  const sessionRef = useRef<any>(null);
  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const streamRef = useRef<MediaStream | null>(null);

  const stopSession = () => {
    if (sessionRef.current) sessionRef.current.close();
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();
    setIsActive(false);
    setIsConnecting(false);
  };

  const startSession = async () => {
    setIsConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

      const instruction = mode === 'character' 
        ? `You are a character from the following story context: "${initialContext || 'A generic fairytale'}". Stay in character, be immersive, and answer naturally.` 
        : 'You are Kitten, a helpful and friendly AI reading companion. Help the user explore their stories.';

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            setIsActive(true);
            const source = audioContextInRef.current!.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(session => session.sendRealtimeInput({ 
                media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } 
              }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
          },
          onmessage: async (message) => {
            if (message.serverContent?.outputTranscription) {
              setCurrentTranscription(prev => prev + message.serverContent!.outputTranscription!.text);
            }
            if (message.serverContent?.turnComplete) {
              if (currentTranscription) {
                setTranscript(prev => [...prev, { role: 'model', text: currentTranscription }]);
                setCurrentTranscription('');
              }
            }
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && audioContextOutRef.current) {
              const ctx = audioContextOutRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.addEventListener('ended', () => sourcesRef.current.delete(source));
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => { stopSession(); },
          onclose: () => { setIsActive(false); }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: instruction,
          outputAudioTranscription: {},
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) { setIsConnecting(false); }
  };

  return (
    <div className="flex-1 flex flex-col h-full bg-[#FDFCFB] animate-in fade-in duration-500">
      <div className="px-6 pt-12 pb-6 flex items-center justify-between">
        <button onClick={onClose} className="p-3 bg-stone-100 rounded-full text-stone-500 hover:bg-stone-200 transition-all">
          <X size={20} />
        </button>
        <div className="flex flex-col items-center">
          <h2 className="serif text-2xl font-bold text-stone-900">Live Studio</h2>
          <div className="flex gap-2 mt-1">
             <button onClick={() => setMode('normal')} className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border transition-all ${mode === 'normal' ? 'bg-blue-600 border-blue-600 text-white' : 'text-stone-400 border-stone-100'}`}>Normal</button>
             <button onClick={() => setMode('character')} className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border transition-all ${mode === 'character' ? 'bg-purple-600 border-purple-600 text-white' : 'text-stone-400 border-stone-100'}`}>Roleplay</button>
          </div>
        </div>
        <div className="w-11" />
      </div>

      <div className="flex-1 overflow-y-auto px-6 py-4 flex flex-col gap-6 hide-scrollbar">
        {transcript.length === 0 && !isActive && !isConnecting && (
          <div className="flex-1 flex flex-col items-center justify-center text-center px-10">
            <div className={`w-20 h-20 ${mode === 'character' ? 'bg-purple-50 text-purple-500' : 'bg-blue-50 text-blue-500'} rounded-[2.5rem] flex items-center justify-center mb-6 shadow-sm`}>
              {mode === 'character' ? <UserCircle size={36} /> : <MessageSquareText size={36} />}
            </div>
            <h3 className="text-xl font-bold text-stone-900 mb-2">{mode === 'character' ? 'Character Roleplay' : 'Voice Companion'}</h3>
            <p className="text-sm text-stone-400 leading-relaxed max-w-[240px]">
              {mode === 'character' ? 'Start a conversation with a character from your story.' : 'Talk to Kitten about your book, themes, or life.'}
            </p>
          </div>
        )}

        <div className="space-y-4">
          {transcript.map((t, i) => (
            <div key={i} className={`flex ${t.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] px-5 py-3.5 rounded-[1.75rem] text-sm font-medium shadow-sm border ${
                t.role === 'user' ? 'bg-blue-50 border-blue-100 text-blue-900 rounded-tr-none' : 'bg-white border-stone-100 text-stone-700 rounded-tl-none'
              }`}>
                {t.text}
              </div>
            </div>
          ))}
          {currentTranscription && (
            <div className="flex justify-start">
              <div className="max-w-[85%] px-5 py-3.5 rounded-[1.75rem] rounded-tl-none text-sm font-medium bg-white border border-stone-100 text-stone-300 shadow-sm animate-pulse italic">
                {currentTranscription}...
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="p-8 flex flex-col items-center gap-6">
        {isActive && (
          <div className="flex items-center gap-2 h-10">
            {[1, 2, 3, 4, 5, 6, 7, 8].map(i => (
              <div key={i} className={`w-1.5 ${mode === 'character' ? 'bg-purple-400' : 'bg-blue-400'} rounded-full animate-wave`} style={{ animationDelay: `${i * 0.1}s`, height: '12px' }} />
            ))}
          </div>
        )}

        <div className="relative">
          {isActive && <div className={`absolute inset-0 ${mode === 'character' ? 'bg-purple-400/20' : 'bg-red-400/20'} rounded-full animate-ping`} />}
          <button 
            onClick={isActive ? stopSession : startSession}
            disabled={isConnecting}
            className={`relative w-24 h-24 rounded-full flex items-center justify-center shadow-xl transition-all duration-300 active:scale-90 ${
              isActive ? (mode === 'character' ? 'bg-purple-600' : 'bg-red-500') : 'bg-blue-600'
            } text-white shadow-lg ${isConnecting ? 'opacity-40 cursor-not-allowed' : ''}`}
          >
            {isConnecting ? <Loader2 size={36} className="animate-spin" /> : isActive ? <MicOff size={36} /> : <Mic size={36} />}
          </button>
        </div>
        <p className="text-[10px] font-black text-stone-400 uppercase tracking-widest">{isConnecting ? 'Establishing Link...' : isActive ? 'Listening Now' : 'Tap to converse'}</p>
      </div>
    </div>
  );
};

export default LiveConversation;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, FileText, Loader2, Globe, Headphones, Mic, ShieldAlert, BookOpen, Layers } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';
import LiveConversation from './components/LiveConversation';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'library' | 'chat'>('library');
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [volume, setVolume] = useState(1.0);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<{ message: string; type?: 'tts' | 'file' | 'web' } | null>(null);
  const [pastedText, setPastedText] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isFetchingUrl, setIsFetchingUrl] = useState(false);
  const [activeInput, setActiveInput] = useState<'url' | 'paste' | null>(null);

  const synthRef = useRef<SpeechSynthesis | null>(typeof window !== 'undefined' ? window.speechSynthesis : null);

  const updateVoices = useCallback(() => {
    if (!synthRef.current) return;
    const allVoices = synthRef.current.getVoices();
    const filtered = allVoices.filter(v => {
      const locale = v.lang.toLowerCase().replace('_', '-');
      return locale.startsWith('en') || locale.startsWith('es');
    });
    if (filtered.length > 0) {
      setVoices(filtered);
      setPlayback(p => (!p.voiceURI ? { ...p, voiceURI: filtered[0].voiceURI } : p));
    }
  }, []);

  useEffect(() => {
    if (!synthRef.current) return;
    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') {
      synthRef.current.onvoiceschanged = updateVoices;
    }
  }, [updateVoices]);

  const stopAudio = useCallback(() => {
    if (synthRef.current) {
      synthRef.current.cancel();
      setPlayback(prev => ({ ...prev, isPlaying: false }));
    }
  }, []);

  const createStory = (title: string, text: string) => {
    if (!text.trim()) return;
    const segments = segmentText(text);
    if (segments.length === 0) return;
    const storyId = btoa(encodeURIComponent(title + text.slice(0, 20))).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ id: `${storyId}-${idx}`, text: s, status: 'idle' }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
    setError(null);
  };

  const fetchFromUrl = async () => {
    if (!urlInput.trim()) return;
    setIsFetchingUrl(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Extract the main story text content from: ${urlInput}.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      createStory(urlInput.split('/').pop() || "Web Story", response.text || "");
    } catch (err: any) {
      setError({ message: "Unable to process URL.", type: 'web' });
    } finally { setIsFetchingUrl(false); }
  };

  const playSegment = useCallback((index: number) => {
    if (!story || !synthRef.current) return;
    stopAudio();
    const segment = story.segments[index];
    if (!segment) return;
    const utter = new SpeechSynthesisUtterance(segment.text);
    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;
    utter.rate = playback.speed;
    utter.volume = volume;
    utter.onend = () => {
      setPlayback(prev => (prev.isPlaying && index + 1 < story.segments.length ? { ...prev, currentSegmentIndex: index + 1 } : { ...prev, isPlaying: false }));
    };
    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, volume, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) playSegment(playback.currentSegmentIndex);
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="h-screen w-full flex flex-col bg-[#FDFCFB] overflow-hidden safe-pb">
      {story ? (
        <Reader 
          story={story} playback={playback} voices={voices} volume={volume}
          onVolumeChange={setVolume} onBack={() => { stopAudio(); setStory(null); }}
          onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
          onSkip={(dir) => setPlayback(p => ({ ...p, currentSegmentIndex: dir === 'next' ? Math.min(p.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(p.currentSegmentIndex - 1, 0), isPlaying: true }))}
          onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
          onPreviewVoice={(vURI) => {}} onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
          onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
        />
      ) : activeTab === 'chat' ? (
        <LiveConversation onClose={() => setActiveTab('library')} />
      ) : (
        <div className="flex-1 flex flex-col px-8 pt-12 pb-8 max-w-lg mx-auto w-full">
          <div className="mb-10 flex items-center justify-between">
            <div>
              <h2 className="serif text-4xl font-bold text-stone-900 tracking-tight leading-none">Kitten.</h2>
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-stone-300 mt-2">AI Storytelling Studio</p>
            </div>
            <div className="bg-stone-100 p-1 rounded-2xl flex gap-1">
              <button onClick={() => setActiveTab('library')} className={`p-2 rounded-xl transition-all ${activeTab === 'library' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400'}`}><BookOpen size={18}/></button>
              <button onClick={() => setActiveTab('chat')} className={`p-2 rounded-xl transition-all ${activeTab === 'chat' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400'}`}><Mic size={18}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto hide-scrollbar flex flex-col gap-5 pb-10">
            {/* Action Cards */}
            <label className="bg-white rounded-[2.5rem] p-6 flex items-center gap-6 shadow-xl shadow-stone-200/40 border border-stone-50 group hover:scale-[1.01] transition-all cursor-pointer">
              <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                 const file = e.target.files?.[0];
                 if (file) { const text = await parseFile(file); createStory(file.name.split('.')[0], text); }
              }} />
              <div className="w-14 h-14 rounded-2xl bg-blue-50 flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all"><Upload size={24}/></div>
              <div className="flex-1">
                <p className="font-bold text-stone-900 text-lg leading-tight">Narrate Document</p>
                <p className="text-[10px] font-bold text-stone-300 uppercase tracking-widest mt-1">PDF, Word, or TXT</p>
              </div>
            </label>

            <div onClick={() => setActiveInput(activeInput === 'url' ? null : 'url')} className="bg-white rounded-[2.5rem] p-6 flex flex-col gap-4 shadow-xl shadow-stone-200/40 border border-stone-50 hover:scale-[1.01] transition-all cursor-pointer">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 rounded-2xl bg-pink-50 flex items-center justify-center text-pink-500"><Globe size={24}/></div>
                <div className="flex-1">
                  <p className="font-bold text-stone-900 text-lg leading-tight">Web Article</p>
                  <p className="text-[10px] font-bold text-stone-300 uppercase tracking-widest mt-1">Extract story from link</p>
                </div>
              </div>
              {activeInput === 'url' && (
                <div className="flex flex-col gap-2 animate-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
                  <input autoFocus placeholder="https://..." className="w-full text-sm p-3 bg-stone-50 border border-stone-100 rounded-xl outline-none" value={urlInput} onChange={e => setUrlInput(e.target.value)} />
                  <button onClick={fetchFromUrl} className="w-full py-3 bg-pink-500 text-white text-[10px] font-black rounded-xl uppercase tracking-[0.2em]">{isFetchingUrl ? <Loader2 size={16} className="animate-spin mx-auto"/> : 'Fetch & Narrate'}</button>
                </div>
              )}
            </div>

            {/* Converse Card - Matches User Image Request */}
            <div onClick={() => setActiveTab('chat')} className="bg-[#141414] rounded-[2.2rem] p-4 flex items-center gap-5 shadow-2xl shadow-stone-900/30 group hover:scale-[1.01] transition-all cursor-pointer border border-white/5">
              <div className="w-14 h-14 rounded-[1.2rem] bg-blue-600 flex items-center justify-center text-white shadow-[0_8px_20px_rgba(37,99,235,0.3)]">
                 <Mic size={24} />
              </div>
              <div className="flex-1">
                <p className="font-bold text-white text-lg leading-none mb-1">Converse</p>
                <p className="text-[10px] font-bold text-[#7A7A7A] uppercase tracking-widest">Real-time Voice AI</p>
              </div>
              <Sparkles className="text-blue-500 mr-2" size={20} />
            </div>

            <div className="mt-4 pt-4 border-t border-stone-100">
               <p className="text-[9px] font-black text-stone-300 uppercase tracking-[0.3em] mb-4 text-center">Featured Lab Tools</p>
               <div className="grid grid-cols-2 gap-3">
                  <div className="p-4 bg-orange-50/50 rounded-3xl border border-orange-100/50 flex flex-col gap-2 group cursor-pointer hover:bg-orange-50 transition-all">
                    <Layers className="text-orange-500" size={18}/>
                    <p className="font-bold text-stone-800 text-xs">Audio Export</p>
                    <p className="text-[8px] text-stone-400 font-medium leading-tight">Bake your stories into WAV podcasts.</p>
                  </div>
                  <div className="p-4 bg-purple-50/50 rounded-3xl border border-purple-100/50 flex flex-col gap-2 group cursor-pointer hover:bg-purple-50 transition-all">
                    <Sparkles className="text-purple-500" size={18}/>
                    <p className="font-bold text-stone-800 text-xs">Illustrate</p>
                    <p className="text-[8px] text-stone-400 font-medium leading-tight">Generate AI scenes for your chapters.</p>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[200] w-full max-w-sm px-4">
