import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Upload, X, AlertCircle, Sparkles, FileText, Loader2, Globe, Headphones, Mic, ShieldAlert, BookOpen, Layers } from 'lucide-react';
import { Story, PlaybackState } from './types';
import { parseFile, segmentText } from './utils/fileParsers';
import Reader from './components/Reader';
import LiveConversation from './components/LiveConversation';
import { GoogleGenAI } from "@google/genai";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'library' | 'chat'>('library');
  const [story, setStory] = useState<Story | null>(null);
  const [voices, setVoices] = useState<SpeechSynthesisVoice[]>([]);
  const [volume, setVolume] = useState(1.0);
  const [playback, setPlayback] = useState<PlaybackState>({
    currentSegmentIndex: 0,
    isPlaying: false,
    isLoading: false,
    voiceURI: '',
    speed: 1.0
  });
  const [error, setError] = useState<{ message: string; type?: 'tts' | 'file' | 'web' } | null>(null);
  const [pastedText, setPastedText] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isFetchingUrl, setIsFetchingUrl] = useState(false);
  const [activeInput, setActiveInput] = useState<'url' | 'paste' | null>(null);

  const synthRef = useRef<SpeechSynthesis | null>(typeof window !== 'undefined' ? window.speechSynthesis : null);

  const updateVoices = useCallback(() => {
    if (!synthRef.current) return;
    const allVoices = synthRef.current.getVoices();

    // Filter specifically for female-sounding English voices, prioritizing Google US English
    const englishVoices = allVoices.filter(v => v.lang.toLowerCase().startsWith('en'));

    if (englishVoices.length > 0) {
      setVoices(englishVoices);
      setPlayback(p => {
        if (!p.voiceURI) {
          // Look for Google US English (Female is standard for this name in most browsers)
          const preferred = englishVoices.find(v => v.name.includes('Google') && v.lang.includes('US')) 
                         || englishVoices.find(v => v.lang.includes('US'))
                         || englishVoices[0];
          return { ...p, voiceURI: preferred.voiceURI };
        }
        return p;
      });
    }
  }, []);

  useEffect(() => {
    if (!synthRef.current) return;
    updateVoices();
    if (typeof synthRef.current.onvoiceschanged !== 'undefined') {
      synthRef.current.onvoiceschanged = updateVoices;
    }

    // Polling fallback
    const interval = setInterval(() => {
      if (voices.length === 0) updateVoices();
      else clearInterval(interval);
    }, 1000);
    return () => clearInterval(interval);
  }, [updateVoices, voices.length]);

  const stopAudio = useCallback(() => {
    if (synthRef.current) {
      synthRef.current.cancel();
      setPlayback(prev => ({ ...prev, isPlaying: false }));
    }
  }, []);

  const createStory = (title: string, text: string) => {
    if (!text.trim()) return;
    const segments = segmentText(text);
    if (segments.length === 0) return;
    const storyId = btoa(encodeURIComponent(title + text.slice(0, 20))).slice(0, 32);
    setStory({
      id: storyId,
      title,
      content: text,
      segments: segments.map((s, idx) => ({ id: `${storyId}-${idx}`, text: s, status: 'idle' }))
    });
    setPlayback(p => ({ ...p, currentSegmentIndex: 0, isPlaying: false }));
    setError(null);
  };

  const fetchFromUrl = async () => {
    if (!urlInput.trim()) return;
    setIsFetchingUrl(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Extract the main story text content from: ${urlInput}.`,
        config: { tools: [{ googleSearch: {} }] }
      });
      createStory(urlInput.split('/').pop() || "Web Story", response.text || "");
    } catch (err: any) {
      setError({ message: "Unable to process URL.", type: 'web' });
    } finally { setIsFetchingUrl(false); }
  };

  const playSegment = useCallback((index: number) => {
    if (!story || !synthRef.current) return;
    stopAudio();
    const segment = story.segments[index];
    if (!segment) return;
    const utter = new SpeechSynthesisUtterance(segment.text);
    const selectedVoice = voices.find(v => v.voiceURI === playback.voiceURI);
    if (selectedVoice) utter.voice = selectedVoice;
    utter.rate = playback.speed;
    utter.volume = volume;
    utter.onend = () => {
      setPlayback(prev => (prev.isPlaying && index + 1 < story.segments.length ? { ...prev, currentSegmentIndex: index + 1 } : { ...prev, isPlaying: false }));
    };
    synthRef.current.speak(utter);
    setPlayback(p => ({ ...p, currentSegmentIndex: index, isPlaying: true }));
  }, [story, voices, playback.voiceURI, playback.speed, volume, stopAudio]);

  useEffect(() => {
    if (playback.isPlaying && story) playSegment(playback.currentSegmentIndex);
  }, [playback.currentSegmentIndex, playback.isPlaying, playSegment]);

  return (
    <div className="h-screen w-full flex flex-col bg-[#FDFCFB] overflow-hidden safe-pb">
      {story ? (
        <Reader 
          story={story} playback={playback} voices={voices} volume={volume}
          onVolumeChange={setVolume} onBack={() => { stopAudio(); setStory(null); }}
          onTogglePlay={() => playback.isPlaying ? stopAudio() : playSegment(playback.currentSegmentIndex)}
          onSkip={(dir) => setPlayback(p => ({ ...p, currentSegmentIndex: dir === 'next' ? Math.min(p.currentSegmentIndex + 1, story.segments.length - 1) : Math.max(p.currentSegmentIndex - 1, 0), isPlaying: true }))}
          onVoiceChange={(vURI) => { stopAudio(); setPlayback(p => ({ ...p, voiceURI: vURI, isPlaying: false })); }}
          onPreviewVoice={(vURI) => {}} onSpeedChange={(s) => setPlayback(p => ({ ...p, speed: s }))}
          onSegmentClick={(idx) => setPlayback(p => ({ ...p, currentSegmentIndex: idx, isPlaying: true }))}
        />
      ) : activeTab === 'chat' ? (
        <LiveConversation onClose={() => setActiveTab('library')} />
      ) : (
        <div className="flex-1 flex flex-col px-8 pt-12 pb-8 max-w-lg mx-auto w-full">
          <div className="mb-10 flex items-center justify-between">
            <div>
              <h2 className="serif text-4xl font-bold text-stone-900 tracking-tight leading-none">Kitten.</h2>
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-stone-300 mt-2">AI Storytelling Studio</p>
            </div>
            <div className="bg-stone-100 p-1 rounded-2xl flex gap-1">
              <button onClick={() => setActiveTab('library')} className={`p-2 rounded-xl transition-all ${activeTab === 'library' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400'}`}><BookOpen size={18}/></button>
              <button onClick={() => setActiveTab('chat')} className={`p-2 rounded-xl transition-all ${activeTab === 'chat' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-400'}`}><Mic size={18}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto hide-scrollbar flex flex-col gap-5 pb-10">
            <label className="bg-white rounded-[2.5rem] p-6 flex items-center gap-6 shadow-xl shadow-stone-200/40 border border-stone-50 group hover:scale-[1.01] transition-all cursor-pointer">
              <input type="file" className="hidden" accept=".pdf,.docx,.txt" onChange={async (e) => {
                 const file = e.target.files?.[0];
                 if (file) { const text = await parseFile(file); createStory(file.name.split('.')[0], text); }
              }} />
              <div className="w-14 h-14 rounded-2xl bg-blue-50 flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all"><Upload size={24}/></div>
              <div className="flex-1">
                <p className="font-bold text-stone-900 text-lg leading-tight">Narrate Document</p>
                <p className="text-[10px] font-bold text-stone-300 uppercase tracking-widest mt-1">PDF, Word, or TXT</p>
              </div>
            </label>

            <div onClick={() => setActiveInput(activeInput === 'url' ? null : 'url')} className="bg-white rounded-[2.5rem] p-6 flex flex-col gap-4 shadow-xl shadow-stone-200/40 border border-stone-50 hover:scale-[1.01] transition-all cursor-pointer">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 rounded-2xl bg-pink-50 flex items-center justify-center text-pink-500"><Globe size={24}/></div>
                <div className="flex-1">
                  <p className="font-bold text-stone-900 text-lg leading-tight">Web Article</p>
                  <p className="text-[10px] font-bold text-stone-300 uppercase tracking-widest mt-1">Extract story from link</p>
                </div>
              </div>
              {activeInput === 'url' && (
                <div className="flex flex-col gap-2 animate-in slide-in-from-top-2" onClick={e => e.stopPropagation()}>
                  <input autoFocus placeholder="https://..." className="w-full text-sm p-3 bg-stone-50 border border-stone-100 rounded-xl outline-none" value={urlInput} onChange={e => setUrlInput(e.target.value)} />
                  <button onClick={fetchFromUrl} className="w-full py-3 bg-pink-500 text-white text-[10px] font-black rounded-xl uppercase tracking-[0.2em]">{isFetchingUrl ? <Loader2 size={16} className="animate-spin mx-auto"/> : 'Fetch & Narrate'}</button>
                </div>
              )}
            </div>

            <div onClick={() => setActiveTab('chat')} className="bg-[#141414] rounded-[2.2rem] p-4 flex items-center gap-5 shadow-2xl shadow-stone-900/30 group hover:scale-[1.01] transition-all cursor-pointer border border-white/50">
              <div className="w-14 h-14 rounded-[1.2rem] bg-blue-600 flex items-center justify-center text-white shadow-[0_8px_20px_rgba(37,99,235,0.3)]">
                 <Mic size={24} />
              </div>
              <div className="flex-1">
                <p className="font-bold text-white text-lg leading-none mb-1">Converse</p>
                <p className="text-[10px] font-bold text-[#7A7A7A] uppercase tracking-widest">Real-time Voice AI</p>
              </div>
              <Sparkles className="text-blue-500 mr-2" size={20} />
            </div>

            <div className="mt-4 pt-4 border-t border-stone-100">
               <p className="text-[9px] font-black text-stone-300 uppercase tracking-[0.3em] mb-4 text-center">Featured Lab Tools</p>
               <div className="grid grid-cols-2 gap-3">
                  <div className="p-4 bg-orange-50/50 rounded-3xl border border-orange-100/50 flex flex-col gap-2 group cursor-pointer hover:bg-orange-50 transition-all">
                    <Layers className="text-orange-500" size={18}/>
                    <p className="font-bold text-stone-800 text-xs">Audio Export</p>
                    <p className="text-[8px] text-stone-400 font-medium leading-tight">Bake your stories into WAV podcasts.</p>
                  </div>
                  <div className="p-4 bg-purple-50/50 rounded-3xl border border-purple-100/50 flex flex-col gap-2 group cursor-pointer hover:bg-purple-50 transition-all">
                    <Sparkles className="text-purple-500" size={18}/>
                    <p className="font-bold text-stone-800 text-xs">Illustrate</p>
                    <p className="text-[8px] text-stone-400 font-medium leading-tight">Generate AI scenes for your chapters.</p>
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[200] w-full max-w-sm px-4">
           <div className="bg-white border p-4 rounded-3xl flex items-center gap-3 shadow-2xl border-stone-100">
              <div className="w-10 h-10 rounded-full bg-red-50 text-red-500 flex items-center justify-center shrink-0"><ShieldAlert size={20}/></div>
              <div className="flex-1 overflow-hidden"><p className="text-[10px] font-black uppercase tracking-widest text-stone-400 mb-0.5">Error</p><p className="text-xs font-bold text-stone-700 leading-tight">{error.message}</p></div>
              <button onClick={() => setError(null)} className="p-2 text-stone-300 hover:text-stone-500"><X size={18}/></button>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, ChevronLeft, X, Volume2, VolumeX, Wand2, Loader2, Download, Image as ImageIcon, Sparkles } from 'lucide-react';
import { Story, PlaybackState } from '../types';
import { GoogleGenAI } from "@google/genai";

interface ReaderProps {
  story: Story;
  playback: PlaybackState;
  voices: SpeechSynthesisVoice[];
  volume: number;
  onVolumeChange: (v: number) => void;
  onBack: () => void;
  onTogglePlay: () => void;
  onSkip: (direction: 'prev' | 'next') => void;
  onVoiceChange: (voiceURI: string) => void;
  onPreviewVoice: (voiceURI: string) => void;
  onSpeedChange: (speed: number) => void;
  onSegmentClick: (index: number) => void;
}

const Reader: React.FC<ReaderProps> = ({ 
  story, 
  playback, 
  voices,
  volume,
  onVolumeChange,
  onBack,
  onTogglePlay, 
  onSegmentClick 
}) => {
  const activeSegmentRef = useRef<HTMLDivElement>(null);
  const [showVolumeSlider, setShowVolumeSlider] = useState(false);
  const [isIllustrating, setIsIllustrating] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [showImageModal, setShowImageModal] = useState(false);
  const volumeTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (activeSegmentRef.current) {
      activeSegmentRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [playback.currentSegmentIndex]);

  const handleVolumeInteraction = (v: number) => {
    onVolumeChange(v);
    if (volumeTimeoutRef.current) window.clearTimeout(volumeTimeoutRef.current);
    volumeTimeoutRef.current = window.setTimeout(() => {
      setShowVolumeSlider(false);
    }, 2000);
  };

  const generateIllustration = async () => {
    setIsIllustrating(true);
    setGeneratedImage(null);
    setShowImageModal(true);

    try {
      const currentText = story.segments[playback.currentSegmentIndex].text;
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            {
              text: `A cinematic, whimsical, and high-quality book illustration for children's story. Style: soft lighting, pastel colors, expressive characters, detailed background. Scene description: ${currentText}`,
            },
          ],
        },
        config: {
          imageConfig: {
            aspectRatio: "1:1"
          },
        },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          const base64Data = part.inlineData.data;
          setGeneratedImage(`data:image/png;base64,${base64Data}`);
          break;
        }
      }
    } catch (error) {
      console.error("Image generation failed:", error);
      setShowImageModal(false);
    } finally {
      setIsIllustrating(false);
    }
  };

  return (
    <div className="h-full flex flex-col bg-[#FDFCFB] max-w-lg mx-auto w-full overflow-hidden safe-pb">
      {/* Top Progress Bar */}
      <div className="pt-6 px-6 flex items-center gap-3">
        <div className="h-1 flex-1 bg-stone-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-blue-500 transition-all duration-700 ease-out" 
            style={{ width: `${((playback.currentSegmentIndex + 1) / story.segments.length) * 100}%` }}
          />
        </div>
        <span className="text-[9px] font-black text-stone-400 tabular-nums uppercase tracking-widest">
          {playback.currentSegmentIndex + 1} / {story.segments.length}
        </span>
      </div>

      {/* Content Area */}
      <div className="flex-1 px-6 pt-8 pb-32 overflow-y-auto hide-scrollbar">
        <h1 className="serif text-2xl font-bold text-stone-900 mb-6 leading-tight opacity-90">{story.title}</h1>
        <div className="space-y-6">
          {story.segments.map((segment, idx) => {
            const isActive = idx === playback.currentSegmentIndex;
            return (
              <div 
                key={idx}
                ref={isActive ? activeSegmentRef : null}
                onClick={() => onSegmentClick(idx)}
                className={`transition-all duration-500 cursor-pointer text-lg md:text-xl font-medium leading-relaxed tracking-tight ${
                  isActive ? 'text-stone-900 opacity-100' : 'text-stone-200 opacity-40 hover:opacity-60'
                }`}
              >
                {segment.text}
              </div>
            );
          })}
        </div>
      </div>

      {/* Control Bar */}
      <div className="fixed bottom-6 left-0 right-0 px-4 z-50 flex justify-center">
        <div className="bg-white/90 backdrop-blur-2xl rounded-full p-2 flex items-center gap-3 shadow-[0_15px_40px_rgba(0,0,0,0.12)] border border-white/50 w-full max-w-sm">

          <button 
            onClick={onBack}
            className="w-10 h-10 rounded-full flex items-center justify-center text-stone-500 hover:bg-stone-50 active:scale-90 transition-all shrink-0"
          >
            <ChevronLeft size={18} />
          </button>

          <button 
              onClick={onTogglePlay}
              className="w-14 h-14 rounded-full bg-blue-600 text-white flex items-center justify-center shadow-lg shadow-blue-200 active:scale-95 transition-all shrink-0"
           >
              {playback.isPlaying ? (
                <Pause size={22} fill="white" />
              ) : (
                <Play size={22} fill="white" className="ml-0.5" />
              )}
           </button>

          {/* AI Illustrator Button */}
          <button 
            onClick={generateIllustration}
            className="w-10 h-10 rounded-full flex items-center justify-center text-purple-600 bg-purple-50 hover:bg-purple-100 active:scale-90 transition-all shrink-0"
            title="Illustrate Current Scene"
          >
            <Wand2 size={18} />
          </button>

          {/* Volume Expansion */}
          <div className="flex-1 flex items-center justify-end gap-1 relative">
            <button 
              onClick={() => setShowVolumeSlider(!showVolumeSlider)}
              className={`w-10 h-10 rounded-full flex items-center justify-center transition-all shrink-0 ${showVolumeSlider ? 'bg-blue-50 text-blue-600' : 'text-stone-500 hover:bg-stone-50'}`}
            >
              {volume === 0 ? <VolumeX size={18} /> : <Volume2 size={18} />}
            </button>

            {showVolumeSlider && (
              <div className="flex items-center gap-2 bg-blue-50/50 rounded-full px-3 py-1.5 animate-in slide-in-from-left-2 fade-in duration-200">
                <input 
                  type="range" min="0" max="1" step="0.01" value={volume} 
                  onChange={e => handleVolumeInteraction(parseFloat(e.target.value))}
                  className="w-16 h-1 accent-blue-600 bg-stone-200 rounded-full appearance-none cursor-pointer"
                  style={{ background: `linear-gradient(to right, #2563eb ${volume * 100}%, #d6d3d1 ${volume * 100}%)` }}
                />
              </div>
            )}
          </div>
        </div>
      </div>

      {/* AI Illustration Modal */}
      {showImageModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 backdrop-blur-xl bg-stone-900/40 animate-in fade-in duration-300">
          <div className="absolute inset-0" onClick={() => !isIllustrating && setShowImageModal(false)} />
          <div className="relative bg-white w-full max-w-sm rounded-[3rem] overflow-hidden shadow-2xl flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-6 border-b border-stone-50 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-stone-900">Scene AI</h3>
                <p className="text-[9px] text-stone-400 font-bold uppercase tracking-widest">Story Illustration</p>
              </div>
              <button 
                onClick={() => setShowImageModal(false)}
                disabled={isIllustrating}
                className="w-10 h-10 rounded-full bg-stone-50 flex items-center justify-center text-stone-400 hover:bg-stone-100 transition-colors disabled:opacity-30"
              >
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 bg-stone-50 flex items-center justify-center p-8 min-h-[300px] relative">
              {isIllustrating ? (
                <div className="flex flex-col items-center gap-4 text-center">
                  <div className="relative">
                    <div className="w-16 h-16 rounded-full border-4 border-purple-100 border-t-purple-600 animate-spin" />
                    <Sparkles className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-purple-600" size={20} />
                  </div>
                  <p className="text-sm font-bold text-stone-500 animate-pulse italic">Painting your scene...</p>
                </div>
              ) : generatedImage ? (
                <img 
                  src={generatedImage} 
                  alt="Story Illustration" 
                  className="w-full h-full object-cover rounded-2xl shadow-lg animate-in fade-in zoom-in-95 duration-500"
                />
              ) : (
                <div className="text-center p-6">
                  <ImageIcon size={48} className="text-stone-200 mx-auto mb-4" />
                  <p className="text-stone-400 text-sm font-medium leading-relaxed">Failed to bring the scene to life. Please try again.</p>
                </div>
              )}
            </div>

            {generatedImage && !isIllustrating && (
              <div className="p-6">
                <a 
                  href={generatedImage} 
                  download={`illustration-${story.id}.png`}
                  className="w-full py-4 bg-stone-900 text-white rounded-2xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-stone-800 transition-colors active:scale-95"
                >
                  <Download size={18} />
                  Save to Gallery
                </a>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

