import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
// Fixed: Added Loader2 to lucide-react imports
import { X, Mic, MicOff, Volume2, Sparkles, MessageSquare, Loader2 } from 'lucide-react';
import { triggerHaptic } from '../utils/nativeBridge';
import { ImpactStyle } from '@capacitor/haptics';

interface LiveConversationProps {
  onClose: () => void;
}

const LiveConversation: React.FC<LiveConversationProps> = ({ onClose }) => {
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [transcription, setTranscription] = useState<string[]>([]);
  const [audioLevel, setAudioLevel] = useState(0);

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Fixed: Manual decode implementation following coding guidelines
  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  // Fixed: Manual encode implementation following coding guidelines to avoid stack limits
  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const startConversation = async () => {
    try {
      setIsConnecting(true);
      triggerHaptic(ImpactStyle.Medium);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      streamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: 'You are a warm, imaginative story companion. You listen to the user and help them brainstorm or narrate parts of a story. Keep responses concise and engaging.',
        },
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            setIsActive(true);

            const source = inputCtx.createMediaStreamSource(streamRef.current!);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);

              // Simple audio level visualization
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setAudioLevel(Math.sqrt(sum / inputData.length));

              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;

              // Use manual encode instead of spread operator to ensure stability
              const base64 = encode(new Uint8Array(int16.buffer));
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData && audioContextRef.current) {
              const ctx = audioContextRef.current;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onclose: () => cleanup(),
          onerror: () => cleanup(),
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      cleanup();
    }
  };

  const cleanup = () => {
    setIsActive(false);
    setIsConnecting(false);
    sessionRef.current?.close();
    streamRef.current?.getTracks().forEach(t => t.stop());
    audioContextRef.current?.close();
  };

  useEffect(() => {
    return () => cleanup();
  }, []);

  return (
    <div className="fixed inset-0 z-[150] bg-stone-900 flex flex-col items-center justify-between safe-pt safe-pb p-8 overflow-hidden">
      <div className="w-full flex justify-between items-center text-white/40">
        <div className="flex items-center gap-2">
          <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
          <span className="text-[10px] font-black uppercase tracking-widest">{isActive ? 'Live' : 'Offline'}</span>
        </div>
        <button onClick={() => { triggerHaptic(); onClose(); }} className="p-2 hover:bg-white/10 rounded-full transition-colors">
          <X size={24} />
        </button>
      </div>

      <div className="flex-1 w-full flex flex-col items-center justify-center gap-12">
        <div className="relative">
          {/* Animated Aura */}
          <div className={`absolute inset-0 bg-blue-500/20 rounded-full blur-3xl transition-all duration-500 ${isActive ? 'scale-150 opacity-100' : 'scale-0 opacity-0'}`} />

          <div className="relative w-48 h-48 rounded-full border border-white/10 flex items-center justify-center bg-white/5 backdrop-blur-3xl shadow-2xl overflow-hidden">
            {isActive ? (
              <div className="flex items-end gap-1.5 h-12">
                {[...Array(8)].map((_, i) => (
                  <div 
                    key={i} 
                    className="w-1.5 bg-blue-400 rounded-full transition-all duration-75"
                    style={{ height: `${Math.max(10, audioLevel * 200 * (0.5 + Math.random()))}%` }}
                  />
                ))}
              </div>
            ) : (
              <Sparkles className="text-blue-400 opacity-20" size={48} />
            )}
          </div>
        </div>

        <div className="text-center max-w-xs space-y-4">
          <h2 className="text-3xl font-bold text-white serif tracking-tight">
            {isConnecting ? 'Waking up...' : isActive ? 'Listening' : 'Ready to chat'}
          </h2>
          <p className="text-stone-400 text-sm leading-relaxed">
            {isActive ? 'Speak naturally. I am here to help you build your story.' : 'Start a real-time voice session with your storytelling companion.'}
          </p>
        </div>
      </div>

      <div className="w-full max-w-sm">
        {!isActive && !isConnecting ? (
          <button 
            onClick={startConversation}
            className="w-full py-5 bg-blue-600 hover:bg-blue-500 text-white rounded-[2rem] font-bold flex items-center justify-center gap-3 shadow-2xl shadow-blue-900/40 transition-all active:scale-95"
          >
            <Mic size={20} />
            Start Conversation
          </button>
        ) : (
          <button 
            onClick={cleanup}
            className="w-full py-5 bg-white/10 hover:bg-white/20 text-white rounded-[2rem] font-bold flex items-center justify-center gap-3 transition-all active:scale-95 border border-white/10"
          >
            {isConnecting ? <Loader2 className="animate-spin" size={20} /> : <MicOff size={20} />}
            {isConnecting ? 'Connecting...' : 'End Session'}
          </button>
        )}
        <p className="text-center mt-6 text-[9px] font-black uppercase tracking-[0.3em] text-white/20 italic">Powered by Gemini Native Audio</p>
      </div>
    </div>
  );
};

